//Based on: https://github.com/microsoft/vscode/blob/94c9ea46838a9a619aeafb7e8afd1170c967bb55/src/vs/base/common/cancellation.ts
import { ICancellationToken, IDisposable } from "../../lib/src/cancellation";

const shortcutEvent = Object.freeze(function (callback: (e: any) => any, context?: any): IDisposable {
    const handle = setTimeout(callback.bind(context), 0);
    return { dispose() { clearTimeout(handle); } };
});

const none: ICancellationToken = Object.freeze({
    isCancellationRequested: false,
    onCancellationRequested: () => { return { dispose: () => { } } }
});

const cancelled: ICancellationToken = Object.freeze({
    isCancellationRequested: true,
    onCancellationRequested: shortcutEvent
});

class MutableToken implements ICancellationToken {

    private _isCancelled: boolean = false;
    private handlers: ((e: any) => any)[] = [];

    public cancel() {
        if (!this._isCancelled) {
            this._isCancelled = true;
            this.handlers.forEach(handler => handler(undefined));
        }
    }

    get isCancellationRequested(): boolean {
        return this._isCancelled;
    }

    public onCancellationRequested(listener: (e: any) => any, thisArgs?: any, disposables?: IDisposable[]): IDisposable {
        if (this._isCancelled) {
            return shortcutEvent(listener, thisArgs);
        }
        this.handlers.push(listener.bind(thisArgs));
        return { dispose: () => { } }
    }

    public dispose(): void {
        this.handlers = [];
    }
}

export class CancellationTokenSource {

    private _token?: ICancellationToken = undefined;
    private _parentListener?: IDisposable = undefined;

    constructor(parent?: ICancellationToken) {
        this._parentListener = parent && parent.onCancellationRequested(this.cancel, this);
    }

    get token(): ICancellationToken {
        if (!this._token) {
            // be lazy and create the token only when
            // actually needed
            this._token = new MutableToken();
        }
        return this._token;
    }

    cancel(): void {
        if (!this._token) {
            // save an object by returning the default
            // cancelled token when cancellation happens
            // before someone asks for the token
            this._token = cancelled;

        } else if (this._token instanceof MutableToken) {
            // actually cancel
            this._token.cancel();
        }
    }

    dispose(cancel: boolean = false): void {
        if (cancel) {
            this.cancel();
        }
        if (this._parentListener) {
            this._parentListener.dispose();
        }
        if (!this._token) {
            // ensure to initialize with an empty token if we had none
            this._token = none;

        } else if (this._token instanceof MutableToken) {
            // actually dispose
            this._token.dispose();
        }
    }
}