import { init as initNetworking } from '../../lib/src/networking';
import { deactivate as deactivateTelemetry } from '../../lib/src/telemetry';
import { AuthManager } from './auth/manager';
import { Context } from '../../lib/src/context';
import { PersistenceManager, makeXdgPersistenceManager } from './persist';
import { CopilotTokenManagerFromGitHubToken } from '../../lib/src/auth/copilotToken';
import { GitHubDeviceFlow } from './auth/deviceFlow';
import { LiveOpenAIFetcher, OpenAIFetcher } from '../../lib/src/openai/openai';
import { getVersion, VscInfo, BlockModeConfig, FixedBlockModeConfig, BlockMode, BuildInfo, ConfigProvider } from '../../lib/src/config';
import { TestMode } from '../../lib/src/testing/testMode';
import { getAllMethods, getAllNotifications, MethodHandlers, NotificationHandlers } from './methods/methods';
import { NoOpStatusReporter, StatusReporter } from '../../lib/src/progress';
import { ConsoleLog, LogTarget, LogVerbose } from '../../lib/src/logger';
import { AgentConfigProvider } from './config';
import { Clock } from '../../lib/src/clock';
import { setupAgentReporters } from './telemetry';
import { CopilotCompletionCache } from './copilotCompletionCache';

const COPILOT_AGENT_VERBOSE = 'COPILOT_AGENT_VERBOSE';

export function init(): Context {
  const ctx = new Context();
  ctx.set(ConfigProvider, new AgentConfigProvider());
  ctx.set(Clock, new Clock());
  ctx.set(BuildInfo, new BuildInfo());
  ctx.set(LogTarget, new ConsoleLog(console));
  ctx.set(TestMode, new TestMode(false));
  const persistenceManager = makeXdgPersistenceManager();
  ctx.set(PersistenceManager, persistenceManager);
  const authManager = new AuthManager(persistenceManager, (ghToken) => new CopilotTokenManagerFromGitHubToken(ghToken));
  ctx.set(GitHubDeviceFlow, new GitHubDeviceFlow());
  ctx.set(AuthManager, authManager);
  const vscInfo: VscInfo = new VscInfo('AGENT_SESSION_UNIMPLEMENTED', 'AGENT_MACHINE_UNIMPLEMENTED', 'AGENT_VERSION_UNIMPLEMENTED');
  ctx.set(VscInfo, vscInfo);
  ctx.set(OpenAIFetcher, new LiveOpenAIFetcher());
  ctx.set(BlockModeConfig, new FixedBlockModeConfig(BlockMode.Server));
  ctx.set(StatusReporter, new NoOpStatusReporter());
  ctx.set(MethodHandlers, getAllMethods());
  ctx.set(NotificationHandlers, getAllNotifications());
  ctx.set(CopilotCompletionCache, new CopilotCompletionCache());

  let agentVerbose = false;
  if (COPILOT_AGENT_VERBOSE in process.env) {
        const val = process.env[COPILOT_AGENT_VERBOSE];
        agentVerbose = (val === '1' || val === 'true');
  }
  ctx.set(LogVerbose, new LogVerbose(agentVerbose));

  initNetworking(getVersion(ctx));
  setupAgentReporters(ctx);

  process.on('exit', () => {
    // attempt to flush reporters (unclear if this will work since only
    // synchronous actions can be performed before exiting)
    deactivateTelemetry();
  });

  // TODO(drifkin): add `unhandledRejection` and `uncaughtException` handlers
  // once we've resolved our approach in
  // <https://github.com/github/copilot/pull/1143>
  return ctx;
}
