import { promises as fs } from 'fs';
import { platform } from 'os';
import { env } from 'process';

/** Persist any state the agent wants to record, in a directory on disk using JSON.
 *  For example, a GitHub token and a record of the user's telemetry consent.
 */
// Note: this is currently always file-based. If we wanted to implement something
// more virtual, e.g. for testing, then we should introduce an abstract base class
// to allow for the variation but still be able to put this in `Context` objects.
export class PersistenceManager {
    constructor(private readonly directory: string) {
    };
    /**
     * Retrieve a piece of state from disk, if present.
     * @param setting The name of the file the state is stored in. `.json` will be appended.
     * @param key The key to lookup inside the file.
     * @returns The value if found, or `undefined` if not.
     */
    async read<T>(setting: string, key: string): Promise<T | undefined> {
        const configFile = `${this.directory}/${setting}.json`;
        try {
            const contents = await fs.readFile(configFile, { encoding: 'utf8' });
            const contentsJSON = JSON.parse(contents as string);
            return contentsJSON[key];
        } catch (e) {
            return undefined;
        }
    }
    /**
     * Update or set a piece of state on disk.
     * @param setting The name of the file to store the state in. `.json` will be appended.
     * @param key The key to store the value under inside the file.
     * @param value The value to store.
     */
    async update<T>(setting: string, key: string, value: T): Promise<void> {
        // TODO this method has a race condition if any other process is trying to
        // read or write this setting file simultaneously. For now this is unlikely
        // so not handled.
        await fs.mkdir(this.directory, { recursive: true, mode: 0o700 });
        const configFile = `${this.directory}/${setting}.json`;
        let contentsJSON: {[key: string]: T} = {};
        try {
            const contents = await fs.readFile(configFile, { encoding: 'utf8' });
            contentsJSON = JSON.parse(contents as string);
        } catch(e) {
            // Ignore
        }
        contentsJSON[key] = value;
        await fs.writeFile(configFile, JSON.stringify(contentsJSON) + '\n', { encoding: 'utf8' });
    }

    async delete(setting: string, key: string): Promise<void> {
        const configFile = `${this.directory}/${setting}.json`;
        try {
            const contents = await fs.readFile(configFile, { encoding: 'utf8' });
            const contentsJSON = JSON.parse(contents as string);
            delete contentsJSON[key];
            await fs.writeFile(configFile, JSON.stringify(contentsJSON) + '\n', { encoding: 'utf8' });
        } catch (e) {
            // Ignore
        }
    }
}

function getXdgConfigPath(): string {
    // There are various approaches to using XDG on non-Linux platforms.
    // For now we just follow what copilot.vim was doing.
    // TODO review this.
    if (env.XDG_CONFIG_HOME) {
        return env.XDG_CONFIG_HOME + '/github-copilot';
    }
    if (platform() === 'win32') {
        return env.USERPROFILE + '\\AppData\\Local\\github-copilot';
    }
    return env.HOME + '/.config/github-copilot';
}

/** Get a `PersistenceManager` that stores state using an appropriate path for the system.
 *  The XDG "config" path is used, in line with what the GitHub CLI does.
 */
export function makeXdgPersistenceManager(): PersistenceManager {
    return new PersistenceManager(getXdgConfigPath());
}
