import { Console } from 'console';
import { TelemetryData, telemetryError } from './telemetry';
import { isProduction, getConfig, ConfigKey } from './config';
import { Context } from './context';
import { Clock } from './clock';

export enum LogLevel {
    DEBUG = 0,
    INFO = 1,
    WARN = 2,
    ERROR = 3,
}


export class LogVerbose {
    constructor(readonly logVerbose: boolean) {}
}

export function verboseLogging(ctx: Context): boolean {
    return ctx.get(LogVerbose).logVerbose;
}


export interface LoggerInterface {
    debug(ctx: Context, msg: string, ...extra: any[]): void;
    info(ctx: Context, msg: string, ...extra: any[]): void;
    warn(ctx: Context, msg: string, ...extra: any[]): void;
    error(ctx: Context, msg: string, ...extra: any[]): void;

    setLevel(level: LogLevel): void;
}

interface Console {
    log(...args: any[]): void;
    warn(...args: any[]): void;
    error(...args: any[]): void;
}
export abstract class LogTarget {
    abstract logIt(ctx: Context, level: LogLevel, message: string, ...extra: any[]): void;
}

export class ConsoleLog extends LogTarget {
    constructor(private readonly console: Console) { super(); }

    logIt(ctx: Context, level: LogLevel, message: string, ...extra: any[]) {
        // Note we don't log INFO or DEBUG messages into console (unless in verbose mode).
        // They are still logged in the output channel.
        if (verboseLogging(ctx) || level == LogLevel.ERROR) {
            this.console.error(message, ...extra);
        } else if (level == LogLevel.WARN) {
            this.console.warn(message, ...extra);
        }
    }
}
export class OutputChannelLog extends LogTarget {
    constructor(private readonly output : { appendLine: (line: string) => void }) { super(); }
    logIt(ctx: Context, level: LogLevel, message: string, ...extra: any[]) {
        this.output.appendLine(`${message} ${extra.map(toPlainText)}`);
    }
}

export class MultiLog extends LogTarget {
    constructor(private readonly targets: LogTarget[]) { super(); }
    logIt(ctx: Context, level: LogLevel, message: string, ...extra: any[]) {
        this.targets.forEach(t => t.logIt(ctx, level, message, ...extra));
    }
}
export class Logger implements LoggerInterface {
    minLoggedLevel: LogLevel;
    context: string;

    constructor(minLoggedLevel: LogLevel, context: string) {
        this.minLoggedLevel = minLoggedLevel;
        this.context = context;
    }

    public setLevel(level: LogLevel) {
        this.minLoggedLevel = level;
    }

    private stringToLevel(s: string|undefined): LogLevel|undefined {
        return LogLevel[s as keyof typeof LogLevel];
    }

    private log(ctx: Context, level: LogLevel, secure: boolean, ...extra: any[]) {
        const levelString = LogLevel[level];

        if (level == LogLevel.ERROR) {
            telemetryError(ctx, "log", TelemetryData.createAndMarkAsIssued({
                'context': this.context,
                'level': levelString,
                'message': extra.length > 0 ? JSON.stringify(extra) : "no msg",
            }), secure);
        }

        if (!this.shouldLog(ctx, level, this.context)) {
            return;
        }

        // Generate timezone aware timestamp
        const timestamp = ctx.get(Clock).now().toISOString();

        const message = `[${levelString}] [${this.context}] [${timestamp}]`;

        ctx.get(LogTarget).logIt(ctx, level, message, ...extra);
    }

    private shouldLog(ctx: Context, level: LogLevel, category: string): boolean {
        if (verboseLogging(ctx)) {
            return true;
        }

        let levels = getConfig<string[]>(ctx, ConfigKey.DebugFilterLogCategories)
        //If any config is set, show only the configured categories
        if (levels.length > 0 && !levels.includes(category)) {
            return false;
        }

        if (isProduction(ctx)) {
            return level >= this.minLoggedLevel;
        }
        // In dev builds, take log level override user pref into account.
        const overrides = getConfig<{[context: string]: string}>(ctx, ConfigKey.DebugOverrideLogLevels);
        const minLevel = this.stringToLevel(overrides['*'])
            ?? this.stringToLevel(overrides[this.context])
            ?? this.minLoggedLevel;
        return level >= minLevel;
    }

    public debug(ctx: Context, ...extra: any[]) {
        this.log(ctx, LogLevel.DEBUG, false /*not secure*/, ...extra);
    }

    public info(ctx: Context, ...extra: any[]) {
        this.log(ctx, LogLevel.INFO, false /*not secure*/, ...extra);
    }

    public warn(ctx: Context, ...extra: any[]) {
        this.log(ctx, LogLevel.WARN, false /*not secure*/, ...extra);
    }

    public error(ctx: Context, ...extra: any[]) {
        this.log(ctx, LogLevel.ERROR, false /*not secure*/, ...extra);
    }

    /**
     * Secure errors will have their extra data logged to secure telemetry,
     * and only their category logged to standard telemetry.
     */
    public secureError(ctx: Context, category: string, ...extra: any[]) {
        this.log(ctx, LogLevel.ERROR, false /*not secure*/, category);
        this.log(ctx, LogLevel.ERROR, true /*secure*/, category, ...extra);
    }
}

function toPlainText(x: unknown): string {
    switch (typeof x) {
        case 'object':
            return JSON.stringify(x);
        default:
            return String(x);
    }
}

export const logger = new Logger(LogLevel.INFO, "default");
