// Number of tokens we limit prompts to.
export const MAX_PROMPT_LENGTH = 1500;
export const DEFAULT_CHARACTER_MULTIPLIER = 3;

export interface RequestId {
    headerRequestId: string;
    completionId: string;
    created: number;
    serverExperiments: string;
    proxyRole: string;
    modelEndpoint: string;
}

export interface ModelInfo {
    modelURL: string;
    temperature: number;
    top_p: number;
    n: number;
    stop: string[];
    max_tokens: number;
}

export interface APIChoice {
    completionText: string;
    meanLogProb: number | undefined;
    meanAlternativeLogProb: number | undefined;
    choiceIndex: number;
    requestId: RequestId;
    modelInfo: ModelInfo | undefined;
    tokens: string[];
    numTokens: number;
    blockFinished: boolean; // Whether the block completion was determined to be finished
}

interface APILogprobs {
    text_offset: number[];
    token_logprobs: number[];
    top_logprobs?: {[key: string]: number}[];
    tokens: string[];
}

export interface APIJsonData {
    text: string;
    logprobs: APILogprobs;
}

export function convertToAPIChoice(ctx: Context,
                                   completionText: string,
                                   jsonData: APIJsonData,
                                   choiceIndex: number,
                                   requestId: RequestId,
                                   blockFinished: boolean,
                                   modelInfo?: ModelInfo): APIChoice {
    logEngineCompletion(ctx, completionText, jsonData, requestId, choiceIndex);

    // NOTE: It's possible that the completion text we care about is not exactly jsonData.text but a prefix,
    // so we pass it down directly.
    return {
        // NOTE: This does not contain stop tokens necessarily
        completionText: completionText,
        meanLogProb: calculateMeanLogProb(ctx, jsonData),
        meanAlternativeLogProb: calculateMeanAlternativeLogProb(ctx, jsonData),
        choiceIndex: choiceIndex,
        requestId: requestId,
        modelInfo: modelInfo,
        blockFinished: blockFinished,
        // NOTE: This contains tokens sampled (including stop tokens)
        tokens: jsonData.logprobs.tokens,
        numTokens: jsonData.logprobs.tokens.length,
    };
}


// only called by content.ts
export async function* cleanupIndentChoices(choices: AsyncIterable<APIChoice>, indentation: string): AsyncIterable<APIChoice> {
    for await (const choice of choices) {
        const choiceCopy = {...choice};
        const completionLines = choiceCopy.completionText.split("\n");
        // Iterate over all lines and trimLeft
        for (let i = 0; i < completionLines.length; ++i) {
            const newLine = completionLines[i].trimLeft();
            if (newLine === "") {
                completionLines[i] = newLine;
            } else {
                completionLines[i] = indentation + newLine;
            }
        }
        // Join the lines again and return
        choiceCopy.completionText = completionLines.join("\n");
        yield choiceCopy;
    }
}


// Helper functions
export function calculateMeanLogProb(ctx: Context, jsonData: APIJsonData): number | undefined {
    if (!jsonData.logprobs.token_logprobs) {
        return undefined;
    }

    try {
        let logProbSum = 0.0;
        let numTokens = 0;

        // Limit to first 50 logprobs, avoids up-ranking longer solutions
        let iterLimit = 50;

        // First token is always null and last token can have multiple options if it hit a stop
        for (let i = 0;
            i < jsonData.logprobs.token_logprobs.length - 1 && iterLimit > 0;
            i++, iterLimit--)
        {
            logProbSum += jsonData.logprobs.token_logprobs[i];
            numTokens += 1;
        }

        if (numTokens > 0) {
            return logProbSum / numTokens;
        } else {
            return undefined;
        }
    } catch (e) {
        logger.error(ctx, `Error calculating mean prob: ${e}`);
    }
}


export function calculateMeanAlternativeLogProb(ctx: Context, jsonData: APIJsonData): number | undefined {
    if (!jsonData.logprobs.top_logprobs) {
        return undefined;
    }

    try {
        let logProbSum = 0.0;
        let numTokens = 0;

        // Limit to first 50 logprobs, avoids up-ranking longer solutions
        let iterLimit = 50;

        for (let i = 0;
            i < jsonData.logprobs.token_logprobs.length - 1 && iterLimit > 0;
            i++, iterLimit--)
        {
            // copy the options object to avoid mutating the original
            const options = {...jsonData.logprobs.top_logprobs[i]};
            delete options[jsonData.logprobs.tokens[i]];
            logProbSum +=  Math.max(...Object.values(options));
            numTokens += 1;
        }

        if (numTokens > 0) {
            return logProbSum / numTokens;
        } else {
            return undefined;
        }
    } catch (e) {
        logger.error(ctx, `Error calculating mean prob: ${e}`);
    }
}

// Returns a temperature in range 0.0-1.0, using either a config setting,
// or the following ranges: 1=0.0, <10=0.2, <20=0.4, >=20=0.8
export function getTemperatureForSamples(ctx: Context, numShots: number): number {
    if (inTestMode(ctx)) {
        return 0.0;
    }
    const configTemp = parseFloat(getConfig(ctx, ConfigKey.Temperature));
    if (configTemp >= 0 && configTemp <= 1) {
        return configTemp;
    }

    if (numShots <= 1) {
        return 0.0;
    } else if (numShots < 10) {
        return 0.2;
    } else if (numShots < 20) {
        return 0.4;
    } else {
        return 0.8;
    }
}
