/** 
 * The type of a constructor that can be passed to `.get()` in order to receive
 * a value of the instance type. 
 */
export type Ctor<T> = abstract new (...args: any[]) => T;

/**
 * Stores a set of singletons and provides type-safe access to them. Create an
 * instance and pass it through function calls.
 */
export class Context {
  private constructionStack: string[] = [];
  private instances = new Map<Ctor<unknown>, unknown>();

  constructor(private readonly baseContext?: Context) {
    const stack = new Error().stack?.split('\n');
    if (stack) {
      // Remove the first line, which is the 'Error:' line.
      this.constructionStack.push(...stack.slice(1));
    }
  }

  /**
   * Returns the instance associated with the given constructor. Throws if there
   * is no binding for it.
   */
  get<T>(ctor: Ctor<T>): T {
    const value = this.tryGet(ctor);
    if (value) {
      return value;
    }
    throw new Error(`No instance of ${ctor.name} has been registered.\n${this}`);
  }

  /**
   * Returns the instance associated with the given constructor.
   * Returns undefined if there is no binding for it.
   */
   private tryGet<T>(ctor: Ctor<T>): T | undefined {
    const value = this.instances.get(ctor);
    if (value) {
      return value as T;
    }
    if (this.baseContext) {
      return this.baseContext.tryGet(ctor);
    }
    return undefined;
  }

  /**
   * Associates the given constructor with the value (an instance of it). Throws
   * if there is an existing binding.
   */
  set<T>(ctor: Ctor<T>, instance: T): void {
    if (this.tryGet(ctor)) {
      throw new Error(`An instance of ${ctor.name} has already been registered. Use forceSet() if you're sure it's a good idea.`);
    }
    this.instances.set(ctor, instance);
  }

  /** 
   * Associates the given constructor with the value (an instance of it).
   * Overrides any existing binding. 
   */
  forceSet<T>(ctor: Ctor<T>, instance: T): void {
    this.instances.set(ctor, instance);
  }

  toString(): string {
    let lines = "    Context created at:\n";
    for (const stackEntry of this.constructionStack || []) {
      lines += `    ${stackEntry}\n`;
    }
    lines += this.baseContext?.toString() ?? '';
    return lines;
  }

  /** 
   * Getter to make it easier to inspect a value in the debug console via
   * autocomplete. 
   */
  get debug(): {[key: string]: unknown} {
    const instances: {[key: string]: unknown} = {};
    for (const [ctor, value] of this.instances) {
      instances[ctor.name] = value;
    }
    return instances;
  }
}