import { DocumentInfo, DocumentInfoWithOffset, getPrompt, PromptInfo, PromptOptions } from '@github/copilot-promptlib';
import Ajv, { DefinedError } from 'ajv';
import { ErrorCode, extractAjvErrors } from '../rpc';
import { MethodResult } from './methods';
import { Context } from '../../../lib/src/context';

export type Params = {
  doc: DocumentInfoWithOffset,
  options: PromptOptions,
  neighbors: DocumentInfo[],
};

const paramsSchema = {
  type: 'object',
  required: ['doc', 'options'],
  properties: {
    doc: {
      type: 'object',
      required: ['source', 'offset', 'languageId'],
      properties: {
        path: { type: 'string'},
        relativePath: { type: 'string' },
        source: { type: 'string' },
        offset: { type: 'number' },
        languageId: { type: 'string' }
        // omitting `fs` since it isn't representable in json
      }
    },
    options: {
      type: 'object',
      required: [],
      properties: {
        maxPromptLength: { type: 'number' },
        languageMarker: { type: 'string' },
        pathMarker: { type: 'string' },
        includeSiblingFunctions: { type: 'string' },
        localImportContext: { type: 'string' },
      }
    },
    neighbors: {
      type: 'array',
      items: {
        type: 'object',
        required: ['source', 'languageId'],
        properties: {
          path: { type: 'string'},
          relativePath: { type: 'string' },
          source: { type: 'string' },
          languageId: { type: 'string' }
        }
      }
    },
  }
};

const ajv = new Ajv();
const _validParams = ajv.compile(paramsSchema);
function validParams(candidate: unknown): candidate is Params {
  return _validParams(candidate);
}

export default async function handleGetPrompt(ctx: Context, params: unknown): Promise<MethodResult<PromptInfo>> {
  if (validParams(params)) {
    const prompt = await getPrompt(params.doc, params.options, params.neighbors);
    return [prompt, null];
  } else {
    const errorMessages = extractAjvErrors(_validParams.errors as DefinedError[]);
    return [null, {
      code: ErrorCode.InvalidParams,
      message: 'Invalid params: ' + errorMessages.join(';')
    }];
  }
}
