import { AbortError } from 'fetch-h2';
import { ClientHttp2Stream } from 'http2';
import * as util from 'util';
import { CopilotTokenManager } from '../auth/copilotToken';
import { asyncIterableFilter, asyncIterableMap } from '../iterableHelpers';
import { logEnginePrompt, now, telemetry, TelemetryData } from '../telemetry';
import { postRequest, Response } from '../networking';
import { logger, Logger, LogLevel } from '../logger';
import {
    APIChoice, getTemperatureForSamples, RequestId
} from './openai';
import { prepareSolutionForReturn, processSSE } from './stream';
import { BlockMode, BlockModeConfig, ConfigKey, getConfig, getLanguageConfig, VscInfo } from '../config';
import { Context } from '../context';
import { StatusReporter } from '../progress';
import { ICancellationToken } from '../cancellation';

const fetchLogger = new Logger(LogLevel.INFO, "fetch");

export enum CopilotUiKind {
    GhostText = "ghostText",
    Panel = "synthesize", // legacy value from the synthesize codelens
    Sidebar = "sidebar" // open-ended prompts from copilot sidebar
}

/** OAI API completion request, along with extra fields specific to Copilot. */
export declare interface CompletionRequest {
    /** Text the model is supposed to complete. */
    prompt: string;
    /** Whether to stream back a response in SSE format. */
    stream: boolean;
    /** Maximum number of tokens the model should generate. */
    max_tokens: number;
    /** How many parallel completions the model should generate (default 1). */
    n: number;
    /** Non-negative temperature sampling parameter (default 1). */
    temperature: number;
    /** Non-negative nucleus sampling parameter (defaults 1). */
    top_p: number;
    /** Strings that will cause the model to stop generating text. */
    stop: string[];
    /** Number of alternative tokens to include logprob data for. */
    logprobs: number;

    /** Copilot-only: names of experimental features to enable in the proxy. */
    feature_flags: string[];
    /** Copilot-only: extra arguments for completion processing. */
    extra: CompletionRequestExtra;
}

/**
 * Completion request arguments that are Copilot-specific and don't exist in
 * the OAI API.
 */
export declare interface CompletionRequestExtra {
    /** The VSCode language ID for the file. */
    language: string;
    /**
     * If set, will let the completion go on until a (non-continuation) line
     * comes through with the given indentation level.
     */
    force_indent?: number;
    /** Number of leading space or tab characters in the next non-empty line. */
    next_indent: number;
}

/**
 * Request parameters other than the prompt, which will be included in the OAI
 * API request.
 */
export declare type PostOptions = Partial<Omit<CompletionRequest, "prompt">>;

// Request helpers

export function getRequestId(response: Response, json?: any): RequestId {
    return {
        headerRequestId: response.headers.get("x-request-id") || "",
        completionId: json && json.id ? json.id : "",
        created: json && json.created ? json.created : 0,
        serverExperiments: response.headers.get("X-Copilot-Experiment") || "",
        proxyRole: response.headers.get("X-Copilot-Proxy-Role") || "",
        modelEndpoint: response.headers.get("X-Copilot-Model-Endpoint") || "",
    };
}

export function getProcessingTime(response: Response): number {
    const reqIdStr = response.headers.get("openai-processing-ms");
    if (reqIdStr) {
        return parseInt(reqIdStr, 10);
    }
    return 0;
}

export function extractEngineName(ctx: Context, engineUrl: string): string {
    // Extract the last path component of the URL
    const engineName = engineUrl.split("/").pop();
    if (!engineName) {
        fetchLogger.error(ctx, "Malformed engine URL: " + engineUrl);
        // Fallback to full URL if there is an error
        return engineUrl;
    }
    return engineName;
}

function uiKindToIntent(uiKind: CopilotUiKind): string | undefined {
    switch (uiKind) {
        case CopilotUiKind.GhostText:
            return "copilot-ghost";
        case CopilotUiKind.Panel:
            return "copilot-panel";
        case CopilotUiKind.Sidebar:
            return "copilot-sidebar";
    }
}

// Request methods

/**
 * Takes a (part of a) completion resolves to the offset of the end of the
 * block, or undefined if the block is not yet finished.
 */
export interface FinishedCallback {
    (text: string): Promise<number | undefined>;
}

export interface CompletionParams {
    prompt: string;
    languageId: string;
    engineUrl: string;
    count: number;
    uiKind: CopilotUiKind;
    allowEmptyChoices?: boolean;
    postOptions?: PostOptions;
}

/** An interface to abstract away the network request to OpenAI, allowing for
 * fake or mock implementations. It's deliberately injected relatively high
 * in the call stack to avoid having to reconstruct some of the lower-level details
 * of the OpenAI API.
 *
 * Currently only used for Ghost Text and Open Copilot, as auto-complete processes
 * the results in a different way.
 */
export abstract class OpenAIFetcher {
    abstract fetchAndStreamCompletions(
        ctx: Context,
        params: CompletionParams,
        finishedCb: FinishedCallback,
        cancellationToken?: ICancellationToken) : Promise<CompletionResults | "Failed" | "Cancelled">;
}


export interface CompletionResults {
    choices: AsyncIterable<APIChoice>;
    getProcessingTime(): number;
}

export function fetchWithInstrumentation(ctx: Context,
                                         prompt: string,
                                         engineUrl: string,
                                         endpoint: string,
                                         request: Partial<CompletionRequest>,
                                         secretKey: string,
                                         vscInfo: VscInfo,
                                         uiKind: CopilotUiKind,
                                         cancel?: ICancellationToken): Promise<Response> | undefined {
    const statusReporter = ctx.get(StatusReporter);
    const uri = util.format('%s/%s', engineUrl, endpoint);
    if (!secretKey) {
        // If not key is set we error
        logger.error(ctx, `Failed to send request to ${uri} due to missing key`);
        return;
    }

    const telemetryData = TelemetryData.createAndMarkAsIssued({
        'endpoint': endpoint,
        'engineName': extractEngineName(ctx, engineUrl),
        'uiKind': uiKind,
    }, {
        'promptCharLen': prompt.length,
    });

    for (const [key, value] of Object.entries(request)) {
        if (key == "prompt") { continue; } // Skip prompt (PII)
        telemetryData.properties[`request.option.${key}`] = JSON.stringify(value) ?? "undefined";
    }

    telemetry(ctx, "request.sent", telemetryData);

    const requestStart = now();
    const intent = uiKindToIntent(uiKind);

    // Wrap the Promise with success/error callbacks so we can log/measure it
    return postRequest(ctx, uri, secretKey, intent, vscInfo, request, cancel).then(response => {
        const requestId = getRequestId(response, undefined);
        telemetryData.extendWithRequestId(requestId);

        // TODO: Add response length (requires parsing)
        const totalTimeMs = now() - requestStart;
        telemetryData.measurements.totalTimeMs = totalTimeMs;

        logger.info(ctx, `request.response: [${uri}] took ${totalTimeMs} ms`);
        logger.debug(ctx, "request.response properties", telemetryData.properties);
        logger.debug(ctx, "request.response measurements", telemetryData.measurements);

        telemetry(ctx, "request.response", telemetryData);

        logEnginePrompt(ctx, prompt, telemetryData);

        return response;
    }).catch(error => {
        statusReporter.setWarning();
        if (error instanceof AbortError) {
            // If we cancelled a network request, we don't want to log a `request.error`
            throw error;
        }
        telemetryData.properties.code = String(error.code ?? "");
        telemetryData.properties.errno = String(error.errno ?? "");
        telemetryData.properties.message = String(error.message ?? "");
        telemetryData.properties.type = String(error.type ?? "");

        const totalTimeMs = now() - requestStart;
        telemetryData.measurements.totalTimeMs = totalTimeMs;

        logger.debug(ctx, `request.response: [${uri}] took ${totalTimeMs} ms`);
        logger.debug(ctx, "request.error properties", telemetryData.properties);
        logger.debug(ctx, "request.error measurements", telemetryData.measurements);

        logger.error(ctx, `Request Error: ${error.message}`);
        telemetry(ctx, "request.error", telemetryData);

        throw error;
    });
}

export function postProcessChoices(choices: AsyncIterable<APIChoice>, allowEmptyChoices?: boolean) {
    if (allowEmptyChoices ?? false) {
        return choices;
    } else {
        return asyncIterableFilter(choices, async (choice) => choice.completionText.trim().length > 0);
    }
}

export class LiveOpenAIFetcher extends OpenAIFetcher {
  async fetchAndStreamCompletions
             (ctx: Context,
              params: CompletionParams,
              finishedCb: FinishedCallback,
              cancel?: ICancellationToken) :
        Promise<CompletionResults | "Failed" | "Cancelled">
    {
        const statusReporter = ctx.get(StatusReporter);
        const stops = getLanguageConfig<string[]>(ctx, ConfigKey.Stops);
        const request: Partial<CompletionRequest> = {
            'prompt': params.prompt,
            'max_tokens': getConfig(ctx, ConfigKey.SolutionLength),
            'temperature': getTemperatureForSamples(ctx, params.count),
            'top_p': getConfig(ctx, ConfigKey.TopP),
            'n': params.count,
            'logprobs': 2,  // Request that logprobs of 2 tokens (i.e. including the best alternative) be returned
            'stop': stops,
        };
        if (ctx.get(BlockModeConfig).forLanguage(ctx, params.languageId) === BlockMode.Server) {
            request['feature_flags'] = ['trim_to_block'];
        }

        if (params.postOptions) {
            Object.assign(request, params.postOptions);
        }

        logger.info(ctx, `[fetchCompletions] engine ${params.engineUrl}`);
        const endpoint = "completions";
        const response = await fetchWithInstrumentation(ctx,
                                                    params.prompt,
                                                    params.engineUrl,
                                                    endpoint,
                                                    request,
                                                    await ctx.get(CopilotTokenManager).getCopilotToken(ctx),
                                                    await ctx.get(VscInfo),
                                                    params.uiKind,
                                                    cancel);
        if (cancel?.isCancellationRequested) {
            const body: NodeJS.ReadableStream = await (response as Response).readable();
            try {
                // Destroy the stream so that the server is hopefully notified we don't want any more data
                // and can cancel/forget about the request itself.
                (body as ClientHttp2Stream).destroy();
            } catch (e) {
                logger.error(ctx, `Error destroying stream: ${e}`);
            }
            statusReporter.setWarning();
            return "Cancelled";
        }

        if (response === undefined) {
            statusReporter.setWarning();
            return "Failed";
        }

        if (response.status !== 200) {
            statusReporter.setWarning();
            // check for 4xx responses which will point to a forbidden
            if (response.status === 401 || response.status === 403) {
                // TODO(drifkin): these actions should probably happen in vsc specific code
                ctx.get(CopilotTokenManager).resetCopilotToken(ctx, response.status);
                return "Failed";
            }
            if (response.status === 410) {
                // Token has expired or invalid, fetch a new one on next request
                ctx.get(CopilotTokenManager).resetCopilotToken(ctx, response.status);
                return "Failed";
            }
            if (response.status === 499) {
                fetchLogger.info(ctx, "Cancelled by server");
                return "Failed";
            }
            const text = await response.text();
            fetchLogger.error(ctx, "Unhandled status from server:", response.status, text);
            return "Failed";
        }
        const choices = asyncIterableMap(processSSE(ctx, response, finishedCb, cancel), async (solution) => prepareSolutionForReturn(ctx, solution));
        return {
            choices: postProcessChoices(choices, params.allowEmptyChoices),
            getProcessingTime: () => getProcessingTime(response as Response)
        };
    }
};