import TelemetryReporter from "vscode-extension-telemetry";
import { getVersion } from "../../lib/src/config";
import { Context } from "../../lib/src/context";
import { APP_INSIGHTS_KEY, APP_INSIGHTS_KEY_SECURE, configureReporter, setTelemetryReporters } from "../../lib/src/telemetry";

function setupReporter(extensionId: string, extensionVersion: string, key: string) {
    const reporter = new TelemetryReporter(extensionId, extensionVersion, key);

    configureReporter(reporter, key);

    return reporter;
}

export function setupAgentReporters(ctx: Context) {
    const extensionId = 'agent';
    const extensionVersion = getVersion(ctx);
    const reporter = setupReporter(extensionId, extensionVersion, APP_INSIGHTS_KEY);
    const reporterSecure = setupReporter(extensionId, extensionVersion, APP_INSIGHTS_KEY_SECURE);
    setTelemetryReporters(reporter, reporterSecure);
}
