import {
  Position as LspPosition,
  Range as LspRange,
} from 'vscode-languageserver-types';

import { TextDocument as LspTextDocument } from 'vscode-languageserver-textdocument';

// 'vscode-languageserver-types' provides `Position` and `Range` types that
// don't match completely, so we need to massage things a bit:

export class Position {
  constructor(line: number, character: number) {
    return LspPosition.create(line, character);
  }
}

export class Range {
  constructor(start: Position, end: Position) {
    return LspRange.create(start as LspPosition, end as LspPosition);
  }
}

export const TextDocument = {
  create: LspTextDocument.create
};

// monkey patch LspTextDocument to include a lineAt method TextDocument is just
// an interface, so let's instantiate a real one (currently (an unexported)
// FullTextDocument, but also who knows what they'll switch to later) and then
// mess with its prototype
const dummyTextDocument = LspTextDocument.create('', '', 0, '');
(Reflect.getPrototypeOf(dummyTextDocument as any) as any).lineAt = function(line: number | Position): any {
  const lineNumber = typeof line === 'number' ? line : (line as LspPosition).line;
  const lines = (this as LspTextDocument).getText().split('\n');
  const text = lines[lineNumber];
  const range = new Range(new Position(lineNumber, 0), new Position(lineNumber, text.length));

  const isEmptyOrWhitespace = text.trim().length === 0;
  return { text, range, isEmptyOrWhitespace };
}

// taken directly from vscode
/**
 * Represents an end of line character sequence in a {@link TextDocument document}.
 */
export enum EndOfLine {
  /**
   * The line feed `\n` character.
   */
  LF = 1,
  /**
   * The carriage return line feed `\r\n` sequence.
   */
  CRLF = 2
}

export enum UIKind {
  Web,
  Desktop
}

