import { CopilotConfigPrefix } from "./constants";
import { Context } from "./context";

const packageJson = require('../../package.json');

export const ConfigKey = {
    Enable: 'enable',
    InlineSuggestEnable: 'inlineSuggest.enable',

    DisplayStyle: ['advanced', 'displayStyle'],
    SecretKey: ['advanced', 'secret_key'],
    SolutionLength: ['advanced', 'length'],
    Stops: ['advanced', 'stops'],
    Temperature: ['advanced', 'temperature'],
    TopP: ['advanced', 'top_p'],
    IndentationMode: ['advanced', 'indentationMode'],
    InlineSuggestCount: ['advanced', 'inlineSuggestCount'],
    ListCount: ['advanced', 'listCount'],

    DebugOverrideProxyUrl: ['advanced', 'debug.overrideProxyUrl'],
    DebugShowScores: ['advanced', 'debug.showScores'],
    DebugOverrideLogLevels: ['advanced', 'debug.overrideLogLevels'],
    DebugFilterLogCategories: ['advanced', 'debug.filterLogCategories'],
};

export type ConfigKeyType = typeof ConfigKey[keyof typeof ConfigKey];

// How to determine where to terminate the completion to the current block.
export enum BlockMode {
    /**
     * Parse the context + completion on the client using treesitter to
     * determine blocks.
     */
    Parsing = "parsing",
    /**
     * Parse the context + completion on the client using indentation-based
     * heuristics to determine blocks.
     */
    Indentation = "indentation",
    /**
     * Let the server parse out blocks and assume that the completion terminates
     * at the end of a block.
     */
    Server = "server",
}

// TODO rework this enum so that the normal/nightly and prod/dev distinctions are orthogonal. (dev builds should behave like nightly?)
export enum BuildType {
    DEV = 'dev',
    PROD = 'prod',
    NIGHTLY = 'nightly'
}

export abstract class BlockModeConfig {
    abstract forLanguage(ctx: Context, languageId: string): BlockMode;
}

export class FixedBlockModeConfig extends BlockModeConfig {
    constructor(private readonly blockMode: BlockMode) {
        super();
    }
    forLanguage(ctx: Context, languageId: string): BlockMode {
        return this.blockMode;
    }
}

export abstract class ConfigProvider {
    abstract getConfig<T>(key: ConfigKeyType): T;
    /**
     * Check whether the setting we got for a particular key
     * is still the default setting or has been overwritten
     * by a user setting (at any level).
     */
    abstract isDefaultSettingOverwritten(key: ConfigKeyType): boolean;
    abstract dumpConfig(): {[key: string]: string};
    abstract getLanguageConfig<T>(key: ConfigKeyType, language?: string): T | undefined;
}

export function getConfigDefaultForKey<T>(key: string): T {
    try {
        const value = packageJson
            .contributes
            .configuration[0]
            .properties[`${CopilotConfigPrefix}.${key}`]
            .default;
        if (value === undefined) {
            throw new Error(`Missing config default value: ${CopilotConfigPrefix}.${key}`);
        }
        return value;
    } catch (e) {
        throw new Error(`Error inspecting config default value ${CopilotConfigPrefix}.${key}: ${e}`);
    }
}

export function getConfigDefaultForObjectKey<T>(key: string, objectKey: string): T {
    try {
        const value = packageJson
            .contributes
            .configuration[0]
            .properties[`${CopilotConfigPrefix}.${key}`]
            .properties[objectKey]
            .default;
        if (value === undefined) {
            throw new Error(`Missing config default value: ${CopilotConfigPrefix}.${key}`);
        }
        return value;
    } catch (e) {
        throw new Error(`Error inspecting config default value ${CopilotConfigPrefix}.${key}.${objectKey}: ${e}`);
    }
}

export function getConfig<T>(ctx: Context, key: ConfigKeyType): T {
    return ctx.get(ConfigProvider).getConfig(key);
}

export function isDefaultSettingOverwritten(ctx: Context, key: typeof ConfigKey[keyof typeof ConfigKey]): boolean {
    return ctx.get(ConfigProvider).isDefaultSettingOverwritten(key);
}

export function dumpConfig(ctx: Context) {
    return ctx.get(ConfigProvider).dumpConfig();
}

export function getLanguageConfig<T>(ctx: Context, key: ConfigKeyType, language?: string): T | undefined {
    return ctx.get(ConfigProvider).getLanguageConfig(key, language);
}

export function getEnabledConfig(ctx: Context, language?: string): boolean | undefined {
    return getLanguageConfig(ctx, ConfigKey.Enable, language);
}

export class BuildInfo {
    // TODO for now this is just initialised from `packageJson` which is the same across agent/extension.
    // Consider reworking this.
    private packageJson = packageJson;
    constructor() {
    }

/**
 * @returns true if this is a build for end users.
 * (for the VSCode extension this is currently either the normal extension or the nightly release)
 */
    isProduction(): boolean {
        return this.getBuildType() != "dev";
}

    getBuildType(): BuildType {
        return this.packageJson.buildType;
}

    getVersion(): string {
        return this.packageJson.version;
    }
}

export function isProduction(ctx: Context): boolean {
    return ctx.get(BuildInfo).isProduction();
}

export function getBuildType(ctx: Context): BuildType {
    return ctx.get(BuildInfo).getBuildType();
}

export function getVersion(ctx: Context): string {
    return ctx.get(BuildInfo).getVersion();
}

