import * as path from 'path';
import { SyntaxNode } from 'web-tree-sitter';
import { getFirstPrecedingComment, parseTree, queryExports } from "./parse";
import { DocumentInfoWithOffset } from "./prompt";
import { FileSystem } from "./fileSystem";


/**
 * Resolve the import `imp`, which is a TypeScript `import` statement appearing in a module whose
 * path is `importerPath`, using `fs`.
 *
 * If the import is not a local import (i.e., the import path does not start with `.`), or the file
 * it imports has an extension other than `.ts`, return `null`.
 */
function resolveLocalTypeScriptImport(importerPath: string, imp: SyntaxNode): string | null {
  let src = imp.namedChild(1)?.text.slice(1, -1);
  if (!src || !src.startsWith("."))
    return null;

  if (path.extname(src) === "") {
    src = src + ".ts";
  } else if (path.extname(src) !== ".ts") {
    return null;
  }


  return path.join(path.dirname(importerPath), src);
}

/**
 * Get a list of all names imported by `imp` (possibly with renaming), where
 * `imp` must be a TypeScript `import` statement.
 */
function getTypescriptImportedNames(imp: SyntaxNode): { name: string, alias: string | undefined }[] {
  let names = [];
  if (imp.namedChild(0)?.type === 'import_clause') {
    let importClause = imp.namedChild(0);
    if (importClause?.namedChild(0)?.type === 'named_imports') {
      let namedImports = importClause.namedChild(0);
      for (let namedImport of namedImports?.namedChildren ?? []) {
        if (namedImport.type === 'import_specifier') {
          const name = namedImport.childForFieldName("name")?.text;
          if (name) {
            const alias = namedImport.childForFieldName("alias")?.text
            names.push({ name, alias });
          }
        }
      }
    }
  }
  return names;
}

/**
 * Module exports are modelled as a mapping from names to lists of declarations.
 *
 * The same name can map to multiple declarations for function signature exports.
 */
type Exports = Map<string, string[]>;

const exportsCache = new Map<string, { mtime: number, exports: Exports }>();

const EXPORTS_CACHE_LOW_WATER_MARK = 1000;
const EXPORTS_CACHE_HIGH_WATER_MARK = 2000;

/**
 * Construct a map representing declarations exported by the file at the given `path`, which is
 * written in language `lang`.
 *
 * For TypeScript, this map associates exported types and functions with the (string representation of)
 * their declarations/signatures.
 *
 * For other languages, declaration extraction is not currently supported, so we always return an
 * empty map.
 */
async function getExportedDeclarations(path: string, lang: string, fs: FileSystem): Promise<Exports> {
  let exports = new Map<string, string[]>();

  let mtime = -1;
  try {
    mtime = await fs.mtime(path);
  } catch {
    // if anything wet wrong getting the mtime, simply report no exports
    return exports;
  }

  let entry = exportsCache.get(path);
  if (entry && entry.mtime === mtime)
    return entry.exports;

  if (lang === "typescript") {
    let tree = null;
    try {
      let srcBytes = await fs.readFile(path);
      let srcString = srcBytes.toString();
      tree = await parseTree(lang, srcString);

      for (let em of queryExports(lang, tree.rootNode)) {
        for (let ec of em.captures) {
          let exp = ec.node;
          if (exp.type === 'export_statement') {
            let decl = exp.childForFieldName("declaration");

            // skip declarations with syntax errors
            if (decl?.hasError()) {
              continue;
            }

            // strip away `declare` if present
            if (decl?.type === 'ambient_declaration') {
              decl = decl.namedChild(0);
            }

            let name, exportedDecl;
            if (decl?.type === 'interface_declaration'
              || decl?.type === 'enum_declaration'
              || decl?.type === 'type_alias_declaration') {
              name = decl.childForFieldName("name")?.text;
              exportedDecl = decl.text;
            } else if (decl?.type === 'function_declaration' || decl?.type === 'function_signature') {
              name = decl.childForFieldName("name")?.text;
              // to turn the function definition into a signature, we prefix it with "declare",
              // remove everything after the return type, and terminate it with a semicolon
              const endIndex = decl.childForFieldName("return_type")?.endIndex ?? decl.childForFieldName("parameters")?.endIndex;
              // if we can't find either return type or parameters, simply skip this function
              if (endIndex === undefined) {
                continue;
              }
              exportedDecl = "declare " + srcString.substring(decl.startIndex, endIndex) + ";";
            }

            if (name) {
              let docComment = getFirstPrecedingComment(exp), docCommentText = "";
              if (docComment) {
                docCommentText = srcString.substring(docComment.startIndex, exp.startIndex);
              }
              let exportedDecls = exports.get(name);
              if (!exportedDecls) {
                exportedDecls = [];
                exports.set(name, exportedDecls);
              }
              exportedDecls.push(docCommentText + exportedDecl);
            }
          }
        }
      }
    } catch {
      // if anything went wrong during reading or parsing the file, simply report no exports
    } finally {
      if (tree)
        tree.delete();
    }
  }

  // if cache has more than EXPORTS_CACHE_HIGH_WATER_MARK entries, remove the oldest entries
  // to bring its size down to EXPORTS_CACHE_LOW_WATER_MARK
  if (exportsCache.size > EXPORTS_CACHE_HIGH_WATER_MARK) {
    for (let key of exportsCache.keys()) {
      exportsCache.delete(key);
      if (exports.size <= EXPORTS_CACHE_LOW_WATER_MARK) {
        break;
      }
    }
  }

  exportsCache.set(path, { mtime, exports });
  return exports;
}

/**
 * Find all import statements in the given subtree.
 */
function getImports(root: SyntaxNode) {
  let imports = [];
  // note that import statements can only appear at the toplevel, so we can simply iterate over
  // the root's children
  for (let toplevelStmt of root.namedChildren) {
    if (toplevelStmt.type === 'import_statement') {
      imports.push(toplevelStmt);
    }
  }
  return imports;
}

/** Regex to match a TypeScript import statement. */
const localImportRegex = /^\s*import\s*(type|)\s*\{[^}]*\}\s*from\s*['"]\./gm;

/**
 * Return the offset of the newline character after the last local import
 * statement in the given string.
 * Returns -1 if the source has no import statements.
 */
function lastLocalImportOffset(source: string): number {
  let lastImport = -1;
  localImportRegex.lastIndex = -1; // restart the regex from the beginning
  let m: RegExpExecArray | null;
  do {
    m = localImportRegex.exec(source);
    if (m) {
      lastImport = localImportRegex.lastIndex + m.length;
    }
  } while (m);

  if (lastImport === -1) {
    return -1;
  }

  const newlineAfterLastImport = source.indexOf("\n", lastImport);
  return newlineAfterLastImport !== -1 ? newlineAfterLastImport : source.length;
}

/**
 * Extract context information from local TypeScript imports.
 */
async function extractTypeScriptLocalImportContext(source: string, path: string, fs: FileSystem): Promise<string[]> {
  let languageId = "typescript";
  let localImportContext: string[] = [];

  // Only parse up to and including the last line containing an import statement
  const lastImportOffset = lastLocalImportOffset(source);
  if (lastImportOffset === -1) {
    return localImportContext;
  }
  source = source.substring(0, lastImportOffset);

  let tree = await parseTree(languageId, source);
  try {
    for (let imp of getImports(tree.rootNode)) {
      let srcPath = resolveLocalTypeScriptImport(path, imp);
      if (!srcPath)
        continue;

      let importedNames = getTypescriptImportedNames(imp);
      if (importedNames.length === 0)
        continue;

      let exports = await getExportedDeclarations(srcPath, languageId, fs);
      for (let importedName of importedNames)
        if (exports.has(importedName.name)) {
          localImportContext.push(...exports.get(importedName.name)!);
          // if the import came through an alias, we could simulate this by adding an alias
          // declaration, but the model seems to figure this out by itself, so we don't
        }
    }
  } finally {
    tree.delete();
  }
  return localImportContext;
}

/**
 * Extract context information from local imports.
 */
export async function extractLocalImportContext(doc: DocumentInfoWithOffset, fs?: FileSystem): Promise<string[]> {
  let { source, path, languageId } = doc;
  if (path && fs)
    if (languageId === "typescript")
      return extractTypeScriptLocalImportContext(source, path, fs);
  return [];
}