import {
    Position,
    Range,
    TextDocument,
} from "vscode";
import { Logger, LogLevel } from "../logger";
import { checkInString, SnippyStringMatch, SnippyToken, SnippyError, lexemeLength } from "./snippylib";
import { telemetry, TelemetryData } from "../telemetry";
import { Context } from "../context";
import { CopilotTokenManager } from "../auth/copilotToken";

const snippyLogger = new Logger(LogLevel.INFO, "snippy");

/** Send a telemetry event about a snippy error **/
function snippyTelemetryError(ctx: Context, error: SnippyError, contextForTelemetry?: { [key: string]: string }): void {
    // If the error was "source too short", we don't want to telemetrize
    if (error.msg.startsWith('"source too short')) {
        return;
    }
    let properties = contextForTelemetry ?? { };
    properties.errorMsg = error.msg;
    properties.errorCode = error.code;
    properties.errorMeta = JSON.stringify(error.meta) ?? "";
    let telemetryData = TelemetryData.createAndMarkAsIssued(properties);
    telemetry(ctx, "snippy.error", telemetryData, true /* secure */);
    snippyLogger.debug(ctx, `Error in calling snippy! Code ${error.code}, message ${error.msg}`);
}

/** Send a telemetry event about a snippy match **/
function snippyTelemetry(ctx: Context, match: SnippyStringMatch, contextForTelemetry?: { [key: string]: string }): void {
    let properties = contextForTelemetry ?? { };
    properties.url = match.url;
    properties.matchedSource = match.matchedSource;
    let measurements = {
        occurrences: match.occurrences,
        matchedCharLength: match.matchedSource.length,
        matchedLexemeLength: lexemeLength(match.matchedSource)
    }
    if (match.foundAt === undefined) {
        snippyLogger.debug(ctx, `Snippy found a match, but it is no longer in the source:\n----\n${match.matchedSource}\n----`);
        properties.removedBeforeSnippyResponded = "true";
    } else {
        snippyLogger.debug(ctx, `Snippy found a match of length ${match.matchedSource.length} at offset ${match.foundAt}.`);
        properties.removedBeforeSnippyResponded = "false";
    }
    let telemetryData = TelemetryData.createAndMarkAsIssued(properties, measurements);
    telemetry(ctx, "snippy.matched", telemetryData, true /* secure */);
}


/**
 *  A matching snippet, for consumption in the UI.
 *  Similar to snippylib.SnippyStringMatch except it is more convenient to apply
 *  for the UI.
 *   - `range`: A range into the current document where the match was found.
 *   - `url`: An example URL that contained matching source.
 *   - `totalMatches`: The total number of matches with `matchedSource`.
 */
 export interface SnippyDocumentMatch {
    range: Range;
    url: string;
    occurrences: number;
    matchedSource: string;
}

export type MatchDocumentCallback = (newDoc: TextDocument) => (SnippyDocumentMatch[])


/**
 * Use Snippy to check for a match in a document around a range of interest.
 * The optional contextForTelemetry are added to telemetry for matching with the completion
 * that triggered the check.
 */
export async function checkInDocument(ctx: Context,
                                      doc: TextDocument,
                                      interestStartOffset: number,
                                      interestLength: number,
                                      contextForTelemetry?: { [key: string]: string }): Promise<MatchDocumentCallback> {
    // Get Snippy's auth token. This is the same as Copilot's auth token, since
    // we're authing using GitHub.
    const copilotToken = await ctx.get(CopilotTokenManager).getCopilotToken(ctx);

    let response = await checkInString({ token: copilotToken } as SnippyToken,
                                       doc.getText(),
                                       [interestStartOffset, interestStartOffset + interestLength]);
    if (response.type === "err") {
        snippyTelemetryError(ctx, response, contextForTelemetry);
        return function (newDoc: TextDocument) { return [] };
    } else {
        let fn = response.fn;
        return function (newDoc: TextDocument) {
            let stringMatches = fn(newDoc.getText());
            // Log and telemetrize each match
            let realMatches = stringMatches.filter(match => {
                if (match.foundAt === undefined) {
                    // Don't telemetrize
                    return false;
                } else {
                    // This line attempts to compute the overlap between the
                    // match and the completion range. This is potentially
                    // imprecise as the document may have changed between the
                    // insertion point and the time of this callback.
                    // Also, it's repeated down in snippyPostCallback.
                    const interestMatchRange = {
                        start: Math.max(match.foundAt, interestStartOffset),
                        end: Math.min(match.foundAt + match.matchedSource.length, interestStartOffset + interestLength)
                    };
                    if (interestMatchRange.start < interestMatchRange.end) {
                        snippyTelemetry(ctx, match, contextForTelemetry);
                    }
                    return true;
                }
            }) as (SnippyStringMatch & { foundAt: number })[]
            // Translate the string matches into document matches
            return realMatches.map(match => {
                    let foundOffset = match.foundAt;
                    let foundPos = newDoc.positionAt(foundOffset);
                    return {
                        range: new Range(foundPos, newDoc.positionAt(foundOffset + match.matchedSource.length)),
                        url: match.url,
                        occurrences: match.occurrences,
                        matchedSource: match.matchedSource
                    }
                });
        }
    }
}


/**
 * Use Snippy to check a completion for the match we'd get if we inserted it into the
 * document. Only send telemetry, don't try to return the matches.
 * The optional contextForTelemetry are added to telemetry for matching with the completion
 * that triggered the check.
 */
 export async function checkInCompletion(
    ctx: Context,
    doc: TextDocument,
    position: Position,
    completion: string,
    contextForTelemetry?: { [key: string]: string }): Promise<void> {

    // Get Snippy's auth token. This is the same as Copilot's auth token, since
    // we're authing using GitHub.
    const copilotToken = await ctx.get(CopilotTokenManager).getCopilotToken(ctx);

    let textWithCompletion = doc.getText(new Range(new Position(0, 0), position)) + completion + doc.getText(new Range(position, new Position(doc.lineCount - 1, doc.lineAt(doc.lineCount - 1).range.end.character)));
    let interestStartOffset = doc.offsetAt(position);
    let interestLength = completion.length;

    let response = await checkInString({ token: copilotToken } as SnippyToken,
                                        textWithCompletion,
                                        [interestStartOffset, interestStartOffset + interestLength]);
    if (response.type === "err") {
        snippyTelemetryError(ctx, response, contextForTelemetry);
    } else {
        let fn = response.fn;
        let stringMatches = fn(textWithCompletion);
        // Log and telemetrize each match
        stringMatches.forEach(match => {
            if (match.foundAt === undefined) {
                // Don't telemetrize
                return false;
            } else {
                // This line attempts to compute the overlap between the
                // match and the completion range. This is potentially
                // imprecise as the document may have changed between the
                // insertion point and the time of this callback.
                // Also, it's repeated down in snippyPostCallback.
                const interestMatchRange = {
                    start: Math.max(match.foundAt, interestStartOffset),
                    end: Math.min(match.foundAt + match.matchedSource.length, interestStartOffset + interestLength)
                };
                if (interestMatchRange.start < interestMatchRange.end) {
                    snippyTelemetry(ctx, match, contextForTelemetry);
                }
            }
        });
    }
}
