import type { TextEditorOptions } from 'vscode';
import { Position, Range, TextDocument } from 'vscode';
import { TelemetryData } from '../telemetry';
import { CompletionResult, ResultType } from './ghostText';
import { normalizeIndentCharacter } from './normalizeIndent';
import { v4 } from 'uuid';

export interface CopilotCompletion {
    uuid: string;
    text: string;
    range: Range;
    telemetry: TelemetryData;
    displayText: string;
    position: Position;
    index: number;
    resultType: ResultType;
}

export function completionsFromGhostTextResults(
    completionResults: CompletionResult[], resultType: ResultType, document: TextDocument,
    position: Position, textEditorOptions?: TextEditorOptions, lastShownCompletionIndex?: number,
) {
    const currentLine = document.lineAt(position);
    let completions = completionResults.map((result) => {
        let range;
        let text = "";
        if (textEditorOptions) {
            result.completion = normalizeIndentCharacter(textEditorOptions, result.completion, currentLine.isEmptyOrWhitespace);
        }
        if (result.completion.displayNeedsWsOffset && currentLine.isEmptyOrWhitespace) {
            // Deindenting case
            range = new Range(new Position(position.line, 0), position)
            text = result.completion.completionText;
        }
        else if (currentLine.isEmptyOrWhitespace && result.completion.completionText.startsWith(currentLine.text)) {
            //If we're at the empty line include leading whitespaces in completion and define range from start of the line
            //This enables stable behavior or deleting whitespaces
            range = new Range(new Position(position.line, 0), position)
            text = result.completion.completionText;
        }
        else {
            // TODO(drifkin): support `getWordRangeAtPosition` in agent
            //Try to extend the suggestion range and text with current word, to reduce jitter while deleting/backspacing
            let wordRange = !process.env.IS_AGENT && document.getWordRangeAtPosition(position);
            if (result.isMiddleOfTheLine) {
                //For middle-of-the-line suggestions we want to replace whole line with the completion
                let line = document.lineAt(position);
                let rangeFromStart = new Range(new Position(position.line, 0), position);
                let textBefore = document.getText(rangeFromStart);
                //If middle-of-the-line suggestion contains rest of the line as suffix include it in the range of the suggestion
                range = result.coversSuffix ? line.range : rangeFromStart;
                text = textBefore + result.completion.displayText
            }
            else if (wordRange) {
                let word = document.getText(wordRange);
                range = new Range(wordRange.start, position);
                text = word + result.completion.completionText;
            }
            else {
                let rangeFromStart = new Range(new Position(position.line, 0), position);
                let textBefore = document.getText(rangeFromStart);
                range = rangeFromStart;
                text = textBefore + result.completion.displayText
            }
        }

        const completion: CopilotCompletion = {
            uuid: v4(),
            text,
            range,
            index: result.completion.completionIndex,
            telemetry: result.telemetry,
            displayText: result.completion.displayText,
            position,
            resultType
        };
        return completion;
    });
    //If we are in typing as suggested flow, we want to put the last displayed completion at the top of the list to keep it selected
    if(resultType === ResultType.TypingAsSuggested && lastShownCompletionIndex !== undefined) {
        let lastShownCompletion = completions.find(predicate => predicate.index === lastShownCompletionIndex);
        if(lastShownCompletion) {
            let restCompletions = completions.filter(predicate => predicate.index !== lastShownCompletionIndex);
            completions = [lastShownCompletion, ...restCompletions];
        }
    }
    return completions;
}
