// Using axios because:
//   - fetch-h2 appears not to support FormData for POST requests
//   - node-fetch has some ES/CommonJS compatibility issues and can't be imported
import * as axios from 'axios';

/**
 * Handle authentication via the GitHub "device flow".
 * This is only currently used by the agent (for non-VSCode editors), and the `axios` dependency
 * means it's better to keep the module in the agent for now to avoid creating a new dependency
 * for the VSCode extension.
 */

const REQUEST1_URL = "https://github.com/login/device/code";
const REQUEST2_URL = "https://github.com/login/oauth/access_token";
const USER_URL = "https://api.github.com/user";
// the copilot-intellij client id
// TODO this should become more generic or be replaced by a test-specific client
const CLIENT_ID = "Iv1.b507a08c87ecfe98"

interface DeviceFlowStage1 {
    user_code: string;
    device_code: string;
    verification_uri: string;
    expires_in: number;
    interval: number;
};

interface DeviceFlowStage2 {
    access_token: string | undefined;
};

async function requestDeviceFlowStage1(): Promise<DeviceFlowStage1> {
    const response = await axios.default.post(REQUEST1_URL,
        {
            client_id: CLIENT_ID,
            scope: "read:user"
        },
        {
            headers: {
                "Accept": "application/json",
            }
        }
    );
    return response.data;
}

async function requestDeviceFlowStage2(deviceCode: string): Promise<DeviceFlowStage2> {
    const response = await axios.default.post(REQUEST2_URL,
        {
            client_id: CLIENT_ID,
            device_code: deviceCode,
            grant_type: "urn:ietf:params:oauth:grant-type:device_code"
        },
        {
            headers: {
                "Accept": "application/json",
            }
        }
    );
    return response.data;
}

interface User {
    login: string;
}

async function requestUserInfo(accessToken: string): Promise<User> {
    const response = await axios.default.get(USER_URL,
        {
            headers: {
                "Authorization": `Bearer ${accessToken}`,
                "Accept": "application/json",
            }
        });
    return response.data;
}

export interface GitHubUser {
    user: string;
    oauth_token: string;
}

export class GitHubDeviceFlow {
    async getToken() {
        const stage1 = await requestDeviceFlowStage1();
        const stage2Promise = new Promise<GitHubUser>(async (resolve, reject) => {
            let expiresIn = stage1.expires_in;
            let accessToken = undefined;
            while (expiresIn > 0) {
                const stage2 = await requestDeviceFlowStage2(stage1.device_code);
                expiresIn -= stage1.interval;
                await new Promise(resolve => setTimeout(resolve, 1000 * stage1.interval));
                accessToken = stage2.access_token;
                if (accessToken) {
                    const userInfo = await requestUserInfo(accessToken);
                    resolve({ user: userInfo.login, oauth_token: accessToken });
                    return;
                }
            }
            reject("Timed out waiting for login to complete");
        });
        return { ...stage1, waitForAuth: stage2Promise };
    };
}
