import { CheckCopilotToken, CopilotTokenManager } from "../../../lib/src/auth/copilotToken";
import { LAST_TELEMETRY_TERMS_UPDATE } from "../../../lib/src/auth/telemetryTerms";
import { Context } from "../../../lib/src/context";
import { PersistenceManager } from "../persist";
import { ErrorCode, RpcError } from "../rpc";

interface AuthRecord {
    user: string;
    oauth_token: string;
}

interface TelemetryRecord {
    version: string;
}

// The invariant we try to maintain in this file is that if we know that user X
// has successfully authed, and we know that user X has consented to telemetry,
// and there has been at least one call to a method that handles authentication,
// such as `checkStatus` (without `localChecksOnly`), `initiateSignIn`, or `getCompletions`,
// then GitHubTokenManager.getCopilotTokenManager() will be set, and otherwise it will be undefined.
//
// Here, "we know" means that either:
//  (a) the user has done it in the current session, or
//  (b) we found a stored record of the user having done it
// and also the user has not done anything to invalidate their auth/telemetry consent
// in the current session (e.g. by re-authing as a different user).
//
// If the stored record changes, e.g. because another process caused an update, we
// will not necessarily notice immediately.

export type AuthStatus =
    // Authentication succeeded and a Copilot token should be available.
    | { status: "OK", user: string }
    // We appear to be logged in but were asked not to connect to the network so can't verify this.
    | { status: "MaybeOK", user: string }
    // The user has not yet signed in to GitHub. Call `signInInitiate` to remedy this.
    | { status: "NotSignedIn" }
    // The user has not yet agreed to the telemetry terms. Obtain their consent and then call `recordTelemetryConsent` to remedy this.
    | { status: "NoTelemetryConsent", user: string }
    // Fatal error: The user is not enabled for Copilot. Less likely, something else went wrong like we got an invalid GitHub token.
    // The client may wish to call `signInInitiate` to give the user a chance to login with a different GitHub user.
    | { status: "NotAuthorized", user: string }
    // Fatal error: The agent failed to get a valid Copilot token for some unknown reason.
    | { status: "FailedToGetToken", user: string }
    // Fatal error: The agent got a Copilot token but it wasn't valid.
    | { status: "TokenInvalid", user: string };

/** A `AuthManager` keeps track of the user's GitHub token and
 *  a `CopilotTokenManager` to manage the associated Copilot token.
*/
export class AuthManager {
    constructor(private readonly persistenceManager: PersistenceManager, private readonly mkTokenManager: (githubToken: string) => CopilotTokenManager & CheckCopilotToken) {
    }
    _copilotTokenManager: (CopilotTokenManager & CheckCopilotToken) | undefined;
    /** Get the current `CopilotTokenManager`, if one is stored. */
    getCopilotTokenManager() {
        return this._copilotTokenManager;
    };

    // Stored by `signInInitiate` for `signInConfirm` to await.
    _pendingSignIn: Promise<AuthStatus> | undefined = undefined;

    setPendingSignIn(promise: Promise<AuthStatus> | undefined): void {
        this._pendingSignIn = promise;
    }

    getPendingSignIn(): Promise<AuthStatus> | undefined {
        return this._pendingSignIn;
    }

    /**
     * Check if Copilot is in good working order, i.e. we believe we will be able
     * to get completions from the server.
     *
     * Note that this can have a side-effect: because we cache a working Copilot token
     * in 'globalCopilotTokenManager, if 'checkStatus' discovers that we aren't authed
     * or don't have telemetry consent now, it will clear the cache. Conversely if
     * we discover we are now authed (maybe some other process did it), it will set
     * the cache.
     *
     * This makes it more likely that the behaviour of Copilot afterwards will be consistent
     * with the result of 'checkStatus'.
     *
     * To only perform local checks, pass 'localChecksOnly: true'.
     */
    async checkAndUpdateStatus(ctx: Context, options?: { localChecksOnly?: boolean }): Promise<AuthStatus> {
        // Except in localChecksOnly mode, before returning this function should always either set
        // a valid token manager, or clear it. If there is already a token manager, and the
        // new state is also to have a working token manager, then it should always leave a
        // working token manager in place, i.e. any other code that runs concurrently should
        // never see a missing token manager.
        const localChecksOnly: boolean = options?.localChecksOnly ?? false;

        let authRecord;

        if (process.env.CODESPACES === 'true' && process.env.GITHUB_TOKEN) {
            // TODO share this with the code in extension/src/session.ts
            authRecord = {
                user: process.env.GITHUB_USER || 'codespace-user',
                oauth_token: process.env.GITHUB_TOKEN,
            };
        }

        if (authRecord === undefined) {
            authRecord = await this.getAuthRecord();
        }

        if (authRecord === undefined) {
            this._copilotTokenManager = undefined;
            return { status: "NotSignedIn" };
        }

        if (localChecksOnly) {
            return { status: "MaybeOK", user: authRecord.user };
        }

        // Even if we have an existing token manager, something may have changed. For example the user might have
        // just become enabled for Copilot, or might have signed in to a different GitHub account.
        // To keep things simple, just create a new one each time.
        const provisionalTokenManager = this.mkTokenManager(authRecord.oauth_token);

        // We do the checks in this order so we tell the user they aren't authorized for Copilot before
        // we suggest they should consent to telemetry.
        const checkTokenResult = await provisionalTokenManager.checkCopilotToken(ctx);
        if (checkTokenResult !== "OK") {
            this._copilotTokenManager = undefined;
            return { status: checkTokenResult.reason, user: authRecord.user };
        }

        const telemetryConsent = await this.getTelemetryConsent(authRecord.user);
        if (telemetryConsent === false) {
            this._copilotTokenManager = undefined;
            return { status: "NoTelemetryConsent", user: authRecord.user };
        }

        this._copilotTokenManager = provisionalTokenManager;
        return { status: "OK", user: authRecord.user };
    }

    async getAuthRecord(): Promise<AuthRecord | undefined> {
        return await this.persistenceManager.read<AuthRecord>('hosts', 'github.com');
    }

    /**
     * Record the user's GitHub token.
     */
    async setAuthRecord(authRecord: AuthRecord) {
        await this.persistenceManager.update<AuthRecord>('hosts', 'github.com', authRecord);
    }

    /**
     * Remove our record of the user's GitHub token.
     */
    async deleteAuthRecord() {
        await this.persistenceManager.delete('hosts', 'github.com');
    }

    async getTelemetryConsent(user: string): Promise<boolean> {
        // TODO ideally this would use the same date-based key logic as VSCode so we can have multiple dates
        // stored at once. However this is moving to the server anyway so it's not worth it for now.
        const saved = await this.persistenceManager.read<TelemetryRecord>('terms', user);
        if (saved?.version && saved.version === LAST_TELEMETRY_TERMS_UPDATE) {
            return true;
        }
        return false;
    }

    /**
     * Record that the user has consented to the current telemetry terms.
     */
    async recordTelemetryConsent(user: string) {
        await this.persistenceManager.update<TelemetryRecord>('terms', user, { version: LAST_TELEMETRY_TERMS_UPDATE });
    }

}

/**
 * Set up a context containing a CopilotTokenManager, based on the current AuthManager.
 * @param ctx The incoming context.
 * @param overrideCopilotTokenManager If supplied, e.g. for testing, this will be used instead of one from the current AuthManager.
 * @returns An overridden context containing a CopilotTokenManager.
 */
export async function createRequestContext(ctx: Context, overrideCopilotTokenManager?: CopilotTokenManager): Promise<Context | RpcError> {
    let tokenManager = overrideCopilotTokenManager;
    if (tokenManager === undefined) {
        // Hopefully there's already a token manager setup.
        tokenManager = ctx.get(AuthManager).getCopilotTokenManager();
    }

    if (tokenManager === undefined) {
        // If not, let's find out why.
        const authResult = await ctx.get(AuthManager).checkAndUpdateStatus(ctx);
        if (authResult.status !== 'OK') {
            return {
                code: ErrorCode.NoCopilotToken,
                message: `Not authenticated: ${authResult.status}`
            };
        }
        tokenManager = ctx.get(AuthManager).getCopilotTokenManager();
        if (tokenManager === undefined) {
            // This case should be impossible because if `checkAndUpdateStatus` returned `OK` then
            // it should have set up a token manager.
            return {
                code: ErrorCode.InternalError,
                message: `Unexpected missing Copilot token`
            };
        }
    }

    const requestCtx = new Context(ctx);
    requestCtx.set(CopilotTokenManager, tokenManager);
    return requestCtx;
}