// General utility functions for all kinds of suggestions (Ghost Text, Open Copilot)

import {
    Position,
    TextDocument
} from 'vscode';
import { isRepetitive } from './anomalyDetection';
import { inTestMode } from './testing/testMode';
import { APIChoice } from './openai/openai';

import { getBlockCloseToken } from './promptLibProxy';
import { checkInCompletion } from './snippy/snippy';
import { telemetry, TelemetryData } from './telemetry';
import { Logger } from './logger';
import { Context } from './context';

/**
 * To avoid double-closing blocks (#272), maybe snip a trailing block-close token
 * from the given completion.
 *
 * We check whether the completion ends with a block-close token, and the next line
 * after the cursor starts with that same token at the same indentation. If so,
 * we snip.
 */
async function maybeSnipCompletion(ctx: Context, doc: TextDocument, position: Position, completion: string, isMiddleOfTheLineSuggestion: boolean): Promise<string> {
    if (completion === "") {
        return completion;
    }

    // Default to `}` for block closing token
    let blockCloseToken = "}"

    //TODO: This should be properly handled in promptlib (in `getBlockCloseToken`)
    //but we don't want to change it before Universe.
    try {
        blockCloseToken = getBlockCloseToken(doc.languageId) ?? "}"
    }
    catch (e) {
        // Ignore errors
    }

    // if the last non-blank line of the completion only consists of the block close token plus whitespace,
    // and the next non-blank line after the insertion position is also only the block close token at the same indentation,
    // then we snip the block close token
    let nextLineStart = completion.length;
    do {
        let thisLineStart = completion.lastIndexOf("\n", nextLineStart - 2) + 1;
        const line = completion.substring(thisLineStart, nextLineStart);
        if (line.trim() === blockCloseToken) {
            for (let i = position.line; i < doc.lineCount; i++) {
                let lineText = doc.lineAt(i).text;
                if (i === position.line) {
                    lineText = lineText.substr(position.character);
                }
                if (lineText.startsWith(line.trimRight())) {
                    //If it's middle-of-the-line suggestion we don't want to trim new line character at the end of the line.
                    return completion.substring(0, Math.max(0, isMiddleOfTheLineSuggestion ? thisLineStart : thisLineStart - 1));
                }
                if (lineText.trim() !== "") {
                    break;
                }
            }
            break;
        }
        if (nextLineStart === thisLineStart) {
            if (inTestMode(ctx)) {
                throw Error(`Aborting: maybeSnipCompletion would have looped on completion: ${completion}`);
            }
            break;
        }
        nextLineStart = thisLineStart;
    } while(nextLineStart > 1);

    return completion;
}

function matchesNextLine(document: TextDocument, position: Position, text: string): boolean {
    let nextLine = "";
    let lineNo: number = position.line+1;
    while (nextLine === "" && lineNo < document.lineCount) {
        nextLine = document.lineAt(lineNo).text.trim();
        if (nextLine === text.trim()) {
            return true;
        }
        lineNo++;
    }
    return false;
}

export async function postProcessChoice(ctx: Context,
                                        insertionCategory: string,
                                        document: TextDocument,
                                        position: Position,
                                        choice: APIChoice,
                                        isMiddleOfTheLineSuggestion: boolean,
                                        logger: Logger) : Promise<APIChoice | undefined>
{
    if (isRepetitive(choice.tokens)) {
        telemetry(ctx, "repetition.detected",
            TelemetryData.createAndMarkAsIssued({
                        // background to the engine.completion event, so no need to repeat all metadata
                        completionId: choice.requestId.completionId,
                        headerRequestId: choice.requestId.headerRequestId,
                        serverExperiments: choice.requestId.serverExperiments,
            }),
            true /*secure*/);
        // FIXME: trim request at start of repetitive block? for now we just skip
        logger.info(ctx, "Filtered out repetitive solution");
        return undefined;
    }

    let postProcessedChoice = {...choice};

    // Avoid single-line completions that duplicate the next line (#993)
    if (matchesNextLine(document, position, postProcessedChoice.completionText)) {
        const baseTelemetryProps = {
            completionId: choice.requestId.completionId,
            headerRequestId: choice.requestId.headerRequestId,
            serverExperiments: choice.requestId.serverExperiments,
        };
        telemetry(ctx, "completion.alreadyInDocument", TelemetryData.createAndMarkAsIssued(baseTelemetryProps));
        telemetry(ctx, "completion.alreadyInDocument", TelemetryData.createAndMarkAsIssued({...baseTelemetryProps, completionTextJson: JSON.stringify(postProcessedChoice.completionText)}), true /*secure*/);
        logger.info(ctx, "Filtered out solution matching next line");
        return undefined;
    }
    // Avoid double-closing blocks (#272)
    postProcessedChoice.completionText = await maybeSnipCompletion(ctx, document, position, postProcessedChoice.completionText, isMiddleOfTheLineSuggestion);

    if (postProcessedChoice.completionText && !process.env.IS_AGENT) {
        // Fire and forget: check for a snippy match and send telemetry if we find one.
        checkInCompletion(ctx, document, position, postProcessedChoice.completionText,
            { uiKind: insertionCategory,
              completionId: postProcessedChoice.requestId.completionId ?? "",
              headerRequestId: postProcessedChoice.requestId.headerRequestId ?? "",
              whenFound: "returnedCompletion"
            });
    }

    return postProcessedChoice.completionText ? postProcessedChoice : undefined;
}

export function checkSuffix(document: TextDocument,
                            position: Position,
                            choice: APIChoice) : boolean {
    let currentLine = document.lineAt(position.line);
    let restOfLine = currentLine.text.substring(position.character);
    if(restOfLine.length > 0) {
        if (choice.completionText.indexOf(restOfLine) !== -1) {
            //If current suggestion contains rest of the line as substring
            //then we will include it in our suggestion range
            return true;
        }
        else {
            let lastIndex = 0;
            for (const c of restOfLine) {
                let idx = choice.completionText.indexOf(c, lastIndex + 1);
                if (idx > lastIndex) {
                    lastIndex = idx;
                }
                else {
                    lastIndex = -1;
                    break;
                }
            }
            return lastIndex !== -1;
        }
    }
    return false;
}
