import { Context } from "../context";
import { telemetry, TelemetryData } from "../telemetry";

/** Send `.shown` event */
export function telemetryShown(ctx: Context, insertionCategory: string, telemetryData: TelemetryData, fromCache: boolean) {
    telemetryData.markAsDisplayed();
    let eventName = fromCache ? `${insertionCategory}.shownFromCache` : `${insertionCategory}.shown`;
    telemetry(ctx, eventName, telemetryData);
}

/** Send `.accepted` event */
export function telemetryAccepted(ctx: Context, insertionCategory: string, telemetryData: TelemetryData) {
    const telemetryName = insertionCategory + ".accepted";
    telemetry(ctx, telemetryName, telemetryData);
}

/** Send `.rejected` event */
export function telemetryRejected(ctx: Context, insertionCategory: string, telemetryData: TelemetryData) {
    const telemetryName = insertionCategory + ".rejected";
    telemetry(ctx, telemetryName, telemetryData);
}