export const ghostTextLogger = new Logger(LogLevel.INFO, "ghostText");

export interface GhostCompletion {
    completionIndex: number
    completionText: string;
    displayText: string;
    displayNeedsWsOffset: boolean;
}

export interface CompletionResult {
    completion: GhostCompletion;
    telemetry: TelemetryData;
    isMiddleOfTheLine: boolean;
    coversSuffix: boolean;
}

export enum ResultType {
    Network,
    Cache,
    TypingAsSuggested,
    Cycling
}

// TODO:(hponde) this state is so that continuing to type will reuse results. It should be
// more like a trie or a prefix tree instead. But works fine since it mitigates when the user
// is typing a log in one file
let lastPrefix: string | undefined = undefined;
let lastPromptHash: string | undefined = undefined;

type CompletionCacheContents = { multiline: boolean, choices: APIChoice[] };

// Given the same prompt (up to white space), we show the same completion
// Note this is not per editor, but that should be ok since it's content based
export const completionCache = new LRUCache<CompletionCacheContents>(100);

/** Requests new completion from OpenAI, should be called if and only if the completions for given prompt were not cached before.
 *  It returns only first completion, additional completions are added to the caches in the background.  */
async function getCompletionsFromNetwork(
   ctx: Context,
   requestContext: RequestContext,
   cancellationToken: ICancellationToken | undefined,
   finishedCb: FinishedCallback): Promise<APIChoice | undefined> {

   ghostTextLogger.debug(ctx, "Getting completions from network");

   const numGhostCompletions = getNumGhostCompletions(ctx, requestContext);
   const temperature = getTemperatureForSamples(ctx, numGhostCompletions);

   const postOptions: PostOptions = {
       "stream": true,
       "n": numGhostCompletions,
       "temperature": temperature,
       "extra": {
           language: requestContext.languageId,
           next_indent: requestContext.indentation.next ?? 0,
       },
   };
   if (!requestContext.multiline) {
       // If we are not in multiline mode, we get the server to truncate the results. This does mean that we
       // also cache a single line result which will be reused even if we are later in multiline mode. This is
       // an acceptable trade-off as the transition should be relatively rare and truncating on the server is
       // more efficient.
       // Note that this also means we don't need to truncate when creating the GhostAPIChoice object below.
       postOptions["stop"] = ['\n'];
   }

   const requestStart = Date.now();
   const engineURL = getEngineURL(ctx);
   const baseTelemetryData = TelemetryData.createAndMarkAsIssued({
       // General fields
       'endpoint': "completions",
       'engineName': extractEngineName(ctx, engineURL),
       'uiKind': CopilotUiKind.GhostText,
       'isCycling': JSON.stringify(requestContext.isCycling),
       // Sampling fields
       'temperature': JSON.stringify(temperature),
       'n': JSON.stringify(numGhostCompletions),
       'stop': JSON.stringify(postOptions["stop"]) ?? "unset",
       }, {
           'promptCharLen': requestContext.prompt.length,
       });

   try {
       const completionParams =
            {
                prompt: requestContext.prompt,
                languageId: requestContext.languageId,
                engineUrl: engineURL,
                count: numGhostCompletions,
                uiKind: CopilotUiKind.GhostText,
                postOptions
            };
       const res = await ctx.get(OpenAIFetcher).fetchAndStreamCompletions(ctx, completionParams, finishedCb, cancellationToken);
       if (res == "Failed") {
           return;
       }

       if (res == "Cancelled") {
           ghostTextLogger.debug(ctx, "Cancelled after awaiting fetchCompletions");
           return;
       }

       const choicesStream: AsyncIterable<APIChoice> = res.choices;
       const choicesIterator = choicesStream[Symbol.asyncIterator]();

       const firstRes = await choicesIterator.next();

       if (firstRes.done) {
           ghostTextLogger.debug(ctx, "All choices redacted");
           return;
       }
       if (cancellationToken?.isCancellationRequested) {
           ghostTextLogger.debug(ctx, "Cancelled after awaiting redactedChoices iterator");
           return;
       }

       const firstChoice: APIChoice = firstRes.value;

       if (firstChoice === undefined) {
           // This is probably unreachable given the firstRes.done check above
           ghostTextLogger.debug(ctx, "Got undefined choice from redactedChoices iterator");
           return;
       }

       const requestTimeMs = Date.now() - requestStart;
       const processingTimeMs = res.getProcessingTime();
       const deltaMs = requestTimeMs - processingTimeMs;

       const telemetryData = baseTelemetryData.extendedBy({
           // Response fields
           'headerRequestId': firstChoice.requestId.headerRequestId,
           'completionId': firstChoice.requestId.completionId,
           'created': firstChoice.requestId.created.toString(),
           'serverExperiments': firstChoice.requestId.serverExperiments,
           'proxyRole': firstChoice.requestId.proxyRole,
           'modelEndpoint': firstChoice.requestId.modelEndpoint,
       }, {
           'completionCharLen': firstChoice.completionText.length,
           'requestTimeMs': requestTimeMs,
           'processingTimeMs': processingTimeMs,
           'deltaMs': deltaMs,
           // Choice properties
           'meanLogProb': firstChoice.meanLogProb || NaN,
           'meanAlternativeLogProb': firstChoice.meanAlternativeLogProb || NaN,
           'numTokens': firstChoice.numTokens,
       });
       telemetry(ctx, "ghostText.performance", telemetryData);

       const remainingChoices = numGhostCompletions - 1;

       ghostTextLogger.debug(ctx, `Awaited first result, id:  ${firstChoice.choiceIndex}`);
       // Adds first result to cache
       addToCache(ctx, requestContext, { multiline: requestContext.multiline, choices: [firstChoice] });

       const remainingPromise = [];
       for (let index = 0; index < remainingChoices; index++) {
           remainingPromise.push(choicesIterator.next());
       }

       //Create promise for all other results, don't `await` it (unless in test mode) but handle asynchronously with `.then()`
       const cacheDone = Promise.all(remainingPromise).then((results) => {
           ghostTextLogger.debug(ctx, `Awaited remaining results, number of results: ${results.length}`);
           const apiChoices = [];
           for (const innerChoice of results) {
               const redactedChoice = innerChoice.value;
               if (redactedChoice === undefined) {
                   continue;
               }
               ghostTextLogger.info(ctx, `GhostText later completion: [${redactedChoice.completionText}]`);
               // NOTE: If the completion has multiple new lines or whitespace at the end, we want to trim that.
               if (redactedChoice.completionText.trimEnd()) {
                   // Collect only unique displayTexts
                   if (apiChoices.findIndex((v) => v.completionText.trim() === redactedChoice.completionText.trim()) !== -1) {
                       continue;
                   }
                   // Collect only different than first choice
                   if (redactedChoice.completionText.trim() === firstChoice.completionText.trim()) {
                       continue;
                   }
                   apiChoices.push(redactedChoice);
               }
           }
           //Append results to current completions cache, and network cache
           if (apiChoices.length > 0) {
               appendToCache(ctx, requestContext, { multiline: requestContext.multiline, choices: apiChoices });
           }
       });
       if (inTestMode(ctx)) {
           await cacheDone;
       }
       // Because we ask the server to stop at \n above, we don't need to force single line here
       return makeGhostAPIChoice(firstRes.value, { forceSingleLine : false });
   } catch (err) {
       // If we cancelled a network request, we don't want to log an error
       if (err instanceof AbortError) {
           const cancelTelemetryData = baseTelemetryData.extendedBy({
               cancelledNetworkRequest: JSON.stringify(true)
           }, {
               timeSinceIssuedMs: Date.now() - requestStart
           });
           telemetry(ctx, "ghostText.canceled", cancelTelemetryData);
       } else {
           ghostTextLogger.error(ctx, `Error on ghost text request ${err}`);
           if (inTestMode(ctx)) {
               throw err;
           }
       }
   }
}

/** Requests new completion from OpenAI, should be called if and only if we are in the servers-side termination mode, and it's follow-up cycling request
 *  It returns all requested completions  */
 async function getAllCompletionsFromNetwork(
    ctx: Context,
    requestContext: RequestContext,
    cancellationToken: ICancellationToken | undefined,
    finishedCb: FinishedCallback): Promise<APIChoice[] | undefined> {

    ghostTextLogger.debug(ctx, "Getting all completions from network");

    const numGhostCompletions = getNumGhostCompletions(ctx, requestContext);
    const temperature = getTemperatureForSamples(ctx, numGhostCompletions);

    const postOptions: PostOptions = {
        "stream": true,
        "n": numGhostCompletions,
        "temperature": temperature,
        "extra": {
            language: requestContext.languageId,
            next_indent: requestContext.indentation.next ?? 0,
        },
    };
    if (!requestContext.multiline) {
        // If we are not in multiline mode, we get the server to truncate the results. This does mean that we
        // also cache a single line result which will be reused even if we are later in multiline mode. This is
        // an acceptable trade-off as the transition should be relatively rare and truncating on the server is
        // more efficient.
        // Note that this also means we don't need to truncate when creating the GhostAPIChoice object below.
        postOptions["stop"] = ['\n'];
    }

    const requestStart = Date.now();
    const engineURL = getEngineURL(ctx);
    const baseTelemetryData = TelemetryData.createAndMarkAsIssued({
        // General fields
        'endpoint': "completions",
        'engineName': extractEngineName(ctx, engineURL),
        'uiKind': CopilotUiKind.GhostText,
        'isCycling': JSON.stringify(requestContext.isCycling),
        // Sampling fields
        'temperature': JSON.stringify(temperature),
        'n': JSON.stringify(numGhostCompletions),
        'stop': JSON.stringify(postOptions["stop"]) ?? "unset",
        }, {
            'promptCharLen': requestContext.prompt.length,
        });

    try {
        const completionParams =
            {
                prompt: requestContext.prompt,
                languageId: requestContext.languageId,
                engineUrl: engineURL,
                count: numGhostCompletions,
                uiKind: CopilotUiKind.GhostText,
                postOptions
            };
        const res = await ctx.get(OpenAIFetcher).fetchAndStreamCompletions(ctx, completionParams, finishedCb, cancellationToken);
        if (res === "Failed") {
            return;
        }
        if (res === "Cancelled") {
            ghostTextLogger.debug(ctx, "Cancelled after awaiting fetchCompletions");
            return;
        }

        const choicesStream: AsyncIterable<APIChoice> = res.choices;
        const apiChoices: APIChoice [] = [];
        for await (const choice of choicesStream) {
            if (cancellationToken?.isCancellationRequested) {
                ghostTextLogger.debug(ctx, "Cancelled after awaiting choices iterator");
                break;
            }
            if (choice.completionText.trimEnd()) {
                // Collect only unique displayTexts
                if (apiChoices.findIndex((v) => v.completionText.trim() === choice.completionText.trim()) !== -1) {
                    continue;
                }
                apiChoices.push(choice);
            }
        }
        //Append results to current completions cache, and network cache
        if (apiChoices.length > 0) {
            appendToCache(ctx, requestContext, { multiline: requestContext.multiline, choices: apiChoices });

            const requestTimeMs = Date.now() - requestStart;
            const processingTimeMs = res.getProcessingTime();
            const deltaMs = requestTimeMs - processingTimeMs;
            const firstChoice = apiChoices[0];
            const telemetryData = baseTelemetryData.extendedBy({
                // Response fields
                'headerRequestId': firstChoice.requestId.headerRequestId,
                'completionId': firstChoice.requestId.completionId,
                'created': firstChoice.requestId.created.toString(),
                'serverExperiments': firstChoice.requestId.serverExperiments,
            }, {
                'completionCharLen': firstChoice.completionText.length,
                'requestTimeMs': requestTimeMs,
                'processingTimeMs': processingTimeMs,
                'deltaMs': deltaMs,
                // Choice properties
                'meanLogProb': firstChoice.meanLogProb || NaN,
                'meanAlternativeLogProb': firstChoice.meanAlternativeLogProb || NaN,
                'numTokens': firstChoice.numTokens,
            });
            telemetry(ctx, "ghostText.cyclingPerformance", telemetryData);
        }
        return apiChoices;
    } catch (err) {
        // If we cancelled a network request, we don't want to log an error
        if (err instanceof AbortError) {
            const cancelTelemetryData = baseTelemetryData.extendedBy({
                cancelledNetworkRequest: JSON.stringify(true)
            }, {
                timeSinceIssuedMs: Date.now() - requestStart
            });
            telemetry(ctx, "ghostText.canceled", cancelTelemetryData);
        } else {
            ghostTextLogger.error(ctx, `Error on ghost text request ${err}`);
            if (inTestMode(ctx)) {
                throw err;
            }
        }
    }
 }

function makeGhostAPIChoice(choice: APIChoice, options: { forceSingleLine: boolean }): APIChoice {
    let ghostChoice = {...choice} as APIChoice;
    ghostChoice.completionText = choice.completionText.trimEnd();
    if (options.forceSingleLine) {
        ghostChoice.completionText = ghostChoice.completionText.split('\n')[0];
    }
    return ghostChoice;
}

function getNumGhostCompletions(ctx: Context, requestContext: RequestContext) {
    if (requestContext.blockMode == BlockMode.Server && requestContext.isCycling) {
        return 2;
    }
    if (requestContext.blockMode == BlockMode.Server) {
        return 1;
    }
    if (requestContext.blockMode == BlockMode.Parsing && requestContext.isCycling && !requestContext.multiline) {
        return 2;
    }
    return requestContext.multiline
        ? getConfig<number>(ctx, ConfigKey.InlineSuggestCount)
        : 1;
}

async function indentationModeCompletionsFromNetwork(
        ctx: Context,
        requestContext: RequestContext,
        cancellationToken?: ICancellationToken): Promise<APIChoice | undefined> {

    ghostTextLogger.debug(ctx, "Getting indentation mode completions from network");
    const temperature = getTemperatureForSamples(ctx, 1);

    const basePostOptions: PostOptions = {
        "stream": true,
        "temperature": temperature,
    };

    const requestStart = Date.now();
    const engineURL = getEngineURL(ctx);
    const baseTelemetryData = TelemetryData.createAndMarkAsIssued({
        // General fields
        'endpoint': "completions",
        'engineName': extractEngineName(ctx, engineURL),
        'uiKind': CopilotUiKind.GhostText,
        'isCycling': JSON.stringify(requestContext.isCycling),
        // Sampling fields
        'temperature': JSON.stringify(temperature),
        'n': JSON.stringify(1),
        'blockMode': 'indentation',
        }, {
            'promptCharLen': requestContext.prompt.length,
        });

    /** Fetch and stream a single completion from the server, and build telemetry */
    async function getSingleCompletion(requestContext: RequestContext, tokenLength: number, previewText: string | undefined): Promise<[APIChoice, TelemetryData] | undefined> {
        const postOptions = { 'max_tokens': tokenLength, ...basePostOptions };
        const completionParams =
            {
                prompt: requestContext.prompt,
                languageId: requestContext.languageId,
                engineUrl: engineURL,
                count: 1,
                uiKind: CopilotUiKind.GhostText,
                allowEmptyChoices: previewText !== undefined,
                postOptions
            };
        const finishedCb = indentationBlockFinished(requestContext.indentation, previewText);
        const res = await ctx.get(OpenAIFetcher).fetchAndStreamCompletions(ctx, completionParams, finishedCb, cancellationToken);
        if (res === "Failed") {
            return;
        }
        if (res === "Cancelled") {
            ghostTextLogger.debug(ctx, "Cancelled after awaiting fetch in single completion");
            return;
        }

        const choicesStream: AsyncIterable<APIChoice> = res.choices;
        const choicesIterator = choicesStream[Symbol.asyncIterator]();
        const choiceIt = await choicesIterator.next();

        if (choiceIt.done) {
            ghostTextLogger.debug(ctx, "No single completion received");
            return;
        }
        if (cancellationToken?.isCancellationRequested) {
            ghostTextLogger.debug(ctx, "Cancelled after awaiting streamChoices in single completion");
            return;
        }

        const choice = choiceIt.value;
        const requestTimeMs = Date.now() - requestStart;
        const processingTimeMs = res.getProcessingTime();
        const deltaMs = requestTimeMs - processingTimeMs;
        const telemetryData = baseTelemetryData.extendedBy({
            // Response fields
            'headerRequestId': choice.requestId.headerRequestId,
            'completionId': choice.requestId.completionId,
            'created': choice.requestId.created.toString(),
            'serverExperiments': choice.requestId.serverExperiments,
            'blockFinished': JSON.stringify(choice.blockFinished) ?? "unknown",
        }, {
            'completionCharLen': choice.completionText.length,
            'requestTimeMs': requestTimeMs,
            'processingTimeMs': processingTimeMs,
            'deltaMs': deltaMs,
            // Choice properties
            'meanLogProb': choice.meanLogProb || NaN,
            'meanAlternativeLogProb': choice.meanAlternativeLogProb || NaN,
            'numTokens': choice.numTokens,
        });
        return [choice, telemetryData];
    }

    try {
        const continuationTokens = getConfig<number>(ctx, ConfigKey.SolutionLength) - PreviewTokens;
        const previewRes = await getSingleCompletion(requestContext, PreviewTokens, undefined /* preview mode */);
        if (previewRes === undefined) {
            return;
        }
        const [preview, previewTelemetryData] = previewRes;
        telemetry(ctx, "ghostText.preview", previewTelemetryData);

        ghostTextLogger.info(ctx, `Received preview. Preview ${preview.blockFinished ? "finished" : "did not finish"} the block`);

        if (preview.blockFinished) {
            // The block was finished in the preview. We add to cache and return.
            addToCache(ctx, requestContext, { multiline: true, choices: [preview] });
            return makeGhostAPIChoice(preview, { forceSingleLine: false });
        } else {
            // TODO: In the background, we also request two other completions from the
            // original prompt, which should populate the cache, but we don't
            // await them.
            //
            // We request a continuation of the preview, and await its return.
            const continRes = await getSingleCompletion({
                ...requestContext,
                prompt: requestContext.prompt + preview.completionText},
                continuationTokens,
                preview.completionText);
            if (continRes === undefined) {
                // Something happened to the continuation. Return what we have
                // but don't add it to cache for a later retry.
                return makeGhostAPIChoice(preview, { forceSingleLine: false });
            }
            const [continuation, continTelemetryData] = continRes;
            const totalTelemetryData = continTelemetryData.extendedBy({
                'previewHeaderRequestId': preview.requestId.headerRequestId,
                'previewCompletionId': preview.requestId.completionId,
            }, {
                'totalCompletionCharLen': preview.completionText.length + continuation.completionText.length,
                'totalRequestTimeMs': previewTelemetryData.measurements.requestTimeMs + continTelemetryData.measurements.requestTimeMs,
                'totalTokens': preview.numTokens + continuation.numTokens,
            });
            telemetry(ctx, "ghostText.continuation", totalTelemetryData);

            const completion: APIChoice = {
                    completionText: preview.completionText + continuation.completionText,
                    meanLogProb: preview.meanLogProb, // NOTE: If preview is < 50 tokens this may be incorrect.
                    meanAlternativeLogProb: preview.meanAlternativeLogProb,
                    choiceIndex: 0,
                    requestId: preview.requestId, // FIXME: Missing the continuation requestId
                    modelInfo: preview.modelInfo,
                    tokens: preview.tokens.concat(continuation.tokens),
                    numTokens: preview.numTokens + continuation.numTokens,
                    blockFinished: continuation.blockFinished,
                }

            ghostTextLogger.info(ctx, `Received continuation. Continuation ${continuation.blockFinished ? "finished" : "did not finish"} the block`);
            // Add to cache and return
            addToCache(ctx, requestContext, { multiline: true, choices: [completion] });
            return makeGhostAPIChoice(completion, { forceSingleLine: false });

        }
    } catch (err) {
        // If we cancelled a network request, we don't want to log an error
        if (err instanceof AbortError) {
            const cancelTelemetryData = baseTelemetryData.extendedBy({
                cancelledNetworkRequest: JSON.stringify(true)
            }, {
                timeSinceIssuedMs: Date.now() - requestStart
            });
            telemetry(ctx, "ghostText.canceled", cancelTelemetryData);
        } else {
            ghostTextLogger.error(ctx, `Error on ghost text request ${err}`);
            if (inTestMode(ctx)) {
                throw err;
            }
        }
    }
}

const debouncedGetCompletionFromNetwork = debouncePromise(getDebounceLimit(), getCompletionsFromNetwork);
const debouncedIndentationModeCompletionsFromNetwork = debouncePromise(getDebounceLimit(), indentationModeCompletionsFromNetwork);

export async function getGhostText(
    ctx: Context,
    document: TextDocument,
    position: Position,
    prompt: Prompt,
    blockMode: BlockMode,
    isCycling: boolean,
    cancellationToken?: ICancellationToken
) : Promise<[CompletionResult[], ResultType] | undefined> {
    const inlineSuggestion = isInlineSuggestion(document, position);
    if (inlineSuggestion === undefined) {
        ghostTextLogger.debug(ctx, "Breaking, invalid middle of the line");
        return;
    }

    const promptText = prompt.prompt;
    const trailingWs = prompt.trailingWs;
    const statusBarItem = ctx.get(StatusReporter);


    let requestMultiline = blockMode === BlockMode.Parsing
                           ? await shouldRequestMultiline(ctx, document, position, inlineSuggestion)
                           : true;
    if (cancellationToken?.isCancellationRequested) {
        ghostTextLogger.info(ctx, "Cancelled after requestMultiline");
        return;
    }
    const [prefix] = trimLastLine(document.getText(new Range(new Position(0, 0), position)));
    const isCyclingRequest = (blockMode === BlockMode.Server && isCycling) || (blockMode == BlockMode.Parsing && isCycling && !requestMultiline) ;
    let choices = getLocalInlineSuggestion(ctx, prefix, promptText, requestMultiline);

    let telemetryData = telemetryIssued(ctx, document, position, prompt, requestMultiline, blockMode, isCyclingRequest);
    let isLocalEnough = (isCyclingRequest && (choices?.[0].length ?? 0) > 1) || (!isCyclingRequest && choices !== undefined);
    if (isLocalEnough) {
        ghostTextLogger.info(ctx, "Found inline suggestions locally");
    } else {
        // No local choices, go to network
        statusBarItem?.setProgress();
        const positionBeforeWS = new Position(position.line, Math.max(position.character - (trailingWs?.length ?? 0), 0));
        const requestContext: RequestContext = {
            blockMode,
            languageId: document.languageId,
            prefix,
            prompt: promptText,
            multiline: requestMultiline,
            indentation: contextIndentation(document, position),
            isCycling
        };
        let networkChoices: APIChoice[] | undefined;
        switch (blockMode) {
            case BlockMode.Indentation:
                let c = await debouncedIndentationModeCompletionsFromNetwork(ctx, requestContext, cancellationToken);
                if (c) {
                    networkChoices = [c];
                }
                break;
            case BlockMode.Server: {
                const noop: FinishedCallback = async text => undefined;
                if(isCyclingRequest) {
                    networkChoices = await getAllCompletionsFromNetwork(ctx, requestContext, cancellationToken, noop);
                }
                else {
                    let c = await debouncedGetCompletionFromNetwork(ctx, requestContext, cancellationToken, noop);
                    if (c) {
                        networkChoices = [c];
                    }
                }
                break;
            }
            case BlockMode.Parsing:
            default: {
                const finishedCb = async (text: string) => {
                    if (!requestMultiline) {
                        // continue to end of completion (stops at newline)
                        return;
                    }
                    return isBlockBodyFinished(document, positionBeforeWS, text);
                };
                if (isCyclingRequest && !requestMultiline) {
                    networkChoices = await getAllCompletionsFromNetwork(ctx, requestContext, cancellationToken, finishedCb);
                }
                else {
                    let c = await debouncedGetCompletionFromNetwork(ctx, requestContext, cancellationToken, finishedCb);
                    if (c) {
                        networkChoices = [c];
                    }
                }
            }
        }
        if (networkChoices && isCyclingRequest) {
            let resultChoices = choices?.[0] ?? [];
            networkChoices.forEach(c => {
                // Collect only unique displayTexts
                if (resultChoices.findIndex((v) => v.completionText.trim() === c.completionText.trim()) !== -1) {
                    return;
                }
                resultChoices.push(c);
            })
            choices = [resultChoices, ResultType.Cycling];
        } else if(networkChoices && !isCyclingRequest) {
            choices = [networkChoices, ResultType.Network];
        }
        statusBarItem?.removeProgress();
    }

    if(!choices) {
        ghostTextLogger.info(ctx, "Breaking, no choices");
        return;
    }
    let [choicesArray, resultType] = choices;

    let postProcessedChoices: AsyncIterable<APIChoice> =
        asyncIterableMapFilter(asyncIterableFromArray(choicesArray),
            async (choice: APIChoice) => postProcessChoice(ctx, "ghostText", document, position, choice, inlineSuggestion, ghostTextLogger)
        );

    let results: CompletionResult [] = [];
    for await (const choice of postProcessedChoices) {
        let hasSuffix = inlineSuggestion && checkSuffix(document, position, choice);

        if (cancellationToken?.isCancellationRequested) {
            ghostTextLogger.info(ctx, "Cancelled after post processing completions");
            return;
        }

        // Do this to get a new object for each choice
        const choiceTelemetryData = telemetryWithAddData(ctx, choice, telemetryData);

        // We want to use `newTrailingWs` as the trailing whitespace
        const ghostCompletion = adjustLeadingWhitespace(choice.choiceIndex, choice.completionText, trailingWs);
        let res = {
            completion: ghostCompletion,
            telemetry: choiceTelemetryData,
            isMiddleOfTheLine: inlineSuggestion,
            coversSuffix: hasSuffix }
        results.push(res);
    }

    return [results, resultType];
}

/**
 * Attempt to get InlineSuggestion locally, in one of two ways:
 *  1. If the user is typing the letters already displayed as inline suggestion.
 *  2. If we have a previously cached inline suggestion for this prompt and requestMultiline.
 */
function getLocalInlineSuggestion(ctx: Context, prefix: string, prompt: string, requestMultiline: boolean): [APIChoice[], ResultType] | undefined {
    let choicesTyping = getCompletionsForUserTyping(ctx, prefix, prompt, requestMultiline);
    if (choicesTyping && choicesTyping.length > 0) {
        return [choicesTyping, ResultType.TypingAsSuggested];
    }

    let choicesCache = getCompletionsFromCache(ctx, prefix, prompt, requestMultiline)
    if (choicesCache && choicesCache.length > 0) {
        return [choicesCache, ResultType.Cache];
    }

    return undefined;
}


/** Info for requesting and caching completions. */
interface RequestContext {
    /** How block trimming should be done. */
    blockMode: BlockMode;
    /** The language of the file. */
    languageId: string;
    /** The text content up to the cursor. */
    prefix: string;
    /** Prompt text to send to the model. */
    prompt: string;
    /** Whether this request should be able to generate multiple lines. */
    multiline: boolean;
    /** Indentation (tabs or spaces) on/before and after the cursor. */
    indentation: ContextIndentation;
    /** Follow up request happening when user requested cycling */
    isCycling: boolean;
}

/** Checks if the position is valid inline suggestion position. Returns `undefined` if it's position where ghost text shouldn't be displayed */
function isInlineSuggestion(document: TextDocument, position: Position) {
    //Checks if we're in the position for the middle of the line suggestion
    const isMiddleOfLine = isMiddleOfTheLine(position, document);
    const isValidMiddleOfLine = isValidMiddleOfTheLinePosition(position, document);

    if (isMiddleOfLine && !isValidMiddleOfLine) {
        return;
    }

    const isInlineSuggestion = isMiddleOfLine && isValidMiddleOfLine;
    return isInlineSuggestion;
}

/** Checks if position is NOT at the end of the line */
function isMiddleOfTheLine(selectionPosition: Position, doc: TextDocument): boolean {
    // must be end of line or trailing whitespace
    const line = doc.lineAt(selectionPosition);
    if (line.text.substr(selectionPosition.character).trim().length != 0) {
        return true;
    }

    return false;
}

/** Checks if position is valid for the middle of the line suggestion */
function isValidMiddleOfTheLinePosition(selectionPosition: Position, doc: TextDocument): boolean {
    const line = doc.lineAt(selectionPosition);
    const endOfLine = line.text.substr(selectionPosition.character).trim();
    return /^\s*[)}\]"'`]*\s*[:{;,]?\s*$/.test(endOfLine);
}

async function shouldRequestMultiline(ctx: Context,
                                      document: TextDocument,
                                      position: Position,
                                      inlineSuggestion: boolean): Promise<boolean> {
    // Parsing long files for multiline completions is slow, so we only do
    // it for files with less than 8000 lines
    // See https://github.com/github/copilot/issues/647
    if (document.lineCount >= 8000) {
        telemetry(ctx, "ghostText.longFileMultilineSkip", TelemetryData.createAndMarkAsIssued({
            languageId: document.languageId,
            lineCount: String(document.lineCount),
            currentLine: String(position.line)
        }));
    } else {
        if (!inlineSuggestion && isSupportedLanguageId(document.languageId)) {
            // Can only check block-level nodes of languages we support
            return await isEmptyBlockStart(document, position);
        } else if (inlineSuggestion && isSupportedLanguageId(document.languageId)) {
            //If we are inline, check if we would suggest multiline for current position or if we would suggest a multiline completion if we were at the end of the line
            return await isEmptyBlockStart(document, position) || await isEmptyBlockStart(document, document.lineAt(position).range.end);
        }
    }
    return false;
}

function getDebounceLimit(): number {
    // Middle of the road debounce based on the inlineDebounceMs experiment
    return 75;
}

/** When we find a completion, keep track of the context it was made for
 *  so that if the user continues typing, we can reuse the results.
*/
function recordLastSuccessfulCompletionContext(prefix: string, promptHash: string) {
    lastPrefix = prefix;
    lastPromptHash = promptHash;
}

/** Add completions to network cache, should be used after successful network call. */
function addToCache(ctx: Context, requestContext: RequestContext, contents: CompletionCacheContents) {
    const promptHash = hashContents(requestContext.prompt);
    recordLastSuccessfulCompletionContext(requestContext.prefix, promptHash);
    completionCache.put(promptHash, contents);
    ghostTextLogger.debug(ctx, `Cached ghost text for key: ${promptHash}, multiline: ${contents.multiline}, number of suggestions: ${contents.choices.length}`);
}

/** Appends completions to existing entry in network cache or creates new entry, should be used after successful network call. */
function appendToCache(ctx: Context, requestContext: RequestContext, newContents: CompletionCacheContents) {
    const promptHash = hashContents(requestContext.prompt);
    const existing = completionCache.get(promptHash);
    if (existing && existing.multiline === newContents.multiline) {
        completionCache.put(promptHash, { multiline: existing.multiline, choices: existing.choices.concat(newContents.choices) });
    }
    else {
        completionCache.put(promptHash, newContents);
    }
    ghostTextLogger.debug(ctx, `Appended cached ghost text for key: ${promptHash}, multiline: ${newContents.multiline}, number of suggestions: ${newContents.choices.length}`);
}

function getCachedChoices(promptHash: string, multiline: boolean): APIChoice[] | undefined {
    const contents = completionCache.get(promptHash);
    if (!contents) {
        return undefined;
    }
    if (multiline && !contents.multiline) {
        // If we've cached a single-line completion but are now in multiline mode,
        // we want to refetch it.
        // On the other hand if we've cached a multiline completion and are now in single-line mode,
        // it's ok to reuse it.
        return undefined;
    }
    return contents.choices;
}

function adjustLeadingWhitespace(index : number, text: string, ws: string): GhostCompletion {
    if (ws.length > 0) {
        if (text.startsWith(ws)) {
            // Remove common prefix so that it can display in the correct position
            return { completionIndex: index, completionText: text, displayText: text.substr(ws.length), displayNeedsWsOffset: false };
        } else {
            // The idea here is that we do want the display to be as close to the final position as possible
            const textLeftWs = text.substr(0, text.length - text.trimLeft().length);
            if (ws.startsWith(textLeftWs)) {
                // NOTE: It's possible that `ws` is a bit too over-indented. Example:
                // def foo(n):
                //     if n > 0:
                //         print(f"n is positive: {n}")
                //         [cursor is here after new line]
                //
                // completion: "    else:"
                return { completionIndex: index, completionText: text, displayText: text.trimLeft(), displayNeedsWsOffset: true };
            } else {
                // We don't know any better so just send `text` back
                return { completionIndex: index, completionText: text, displayText: text, displayNeedsWsOffset: false };
            }
        }
    } else {
        // If we do not know leading whitespace or if it is an empty string, just return input text
        return { completionIndex: index, completionText: text, displayText: text, displayNeedsWsOffset: false };
    }
}

/** Returns completions for *user-is-typing-as-suggested* flow */
function getCompletionsForUserTyping(ctx: Context, prefix: string, prompt: string, multiline: boolean) {
    if (!lastPrefix || !lastPromptHash || !prefix.startsWith(lastPrefix)) {
        return undefined;
    }

    const lastCachedCompletion = getCachedChoices(lastPromptHash, multiline);
    if (!lastCachedCompletion) {
        return undefined;
    }
    const remainingPrefix = prefix.substring(lastPrefix.length);

    ghostTextLogger.debug(ctx, `Getting completions for user-typing flow - remaining prefix: ${remainingPrefix}`);

    const completionsToReturn: APIChoice[] = [];
    lastCachedCompletion.forEach(element => {
        // NOTE: make sure to return a new object
        const completionToReturn = makeGhostAPIChoice(element, { forceSingleLine : false });
        if (completionToReturn.completionText.startsWith(remainingPrefix)) {
            completionToReturn.completionText = completionToReturn.completionText.substring(remainingPrefix.length);
            completionsToReturn.push(completionToReturn);
        }

    });
    return completionsToReturn;
}

/** Returns all completions from the network cache for given promptHash */
function getCompletionsFromCache(ctx: Context, prefix: string, prompt: string, multiline: boolean): APIChoice[] | undefined {
    const promptHash = hashContents(prompt);
    ghostTextLogger.debug(ctx, `Trying to get completions from cache for key: ${promptHash}`);
    const cachedChoice = getCachedChoices(promptHash, multiline);
    if (cachedChoice) {
        ghostTextLogger.debug(ctx, `Got completions from cache for key: ${promptHash}`);
        const completionsToReturn: APIChoice[] = [];
        cachedChoice.forEach(element => {
            // NOTE: make sure to return a new object
            const completionToReturn = makeGhostAPIChoice(element, { forceSingleLine : !multiline });
            completionsToReturn.push(completionToReturn);
        });

        const result = completionsToReturn.filter(e => e.completionText);
        if (result.length > 0) {
            recordLastSuccessfulCompletionContext(prefix, promptHash);
        }
        return result;
    }
}

/** Return new object with added information about the ghost text result to telemetry data */
function telemetryWithAddData(ctx: Context, choice: APIChoice, telemetryData: TelemetryData): TelemetryData {
    const requestId = choice.requestId;
    const properties: { [key: string]: string } = {
        "headerRequestId": requestId.headerRequestId,
        "completionId": requestId.completionId,
        "choiceIndex": choice.choiceIndex.toString(),
        "created": requestId.created.toString(),
        "serverExperiments": requestId.serverExperiments,
    };
    const measurements: { [key: string]: number } = {
        "numTokens": choice.numTokens,
        "compCharLen": choice.completionText.length,
        "numLines": choice.completionText.split("\n").length,
    };
    // Add assessments
    if (choice.meanLogProb) {
        measurements.meanLogProb = choice.meanLogProb;
    }
    if (choice.meanAlternativeLogProb) {
        measurements.meanAlternativeLogProb = choice.meanAlternativeLogProb;
    }

    const extendedTelemetry = telemetryData.extendedBy(properties, measurements);
    // Compute confidence
    extendedTelemetry.measurements.confidence = ghostTextScoreConfidence(ctx, extendedTelemetry);
    extendedTelemetry.measurements.quantile = ghostTextScoreQuantile(ctx, extendedTelemetry);
    ghostTextLogger.debug(ctx, `Extended telemetry for ${
        telemetryData.properties.headerRequestId} with retention confidence ${
            extendedTelemetry.measurements.confidence} (expected as good or better than about ${
                extendedTelemetry.measurements.quantile} of all suggestions)`);
    return extendedTelemetry;
}

/** Create telemetry data and send `ghostText.issued` event */
function telemetryIssued(ctx: Context, document: TextDocument, position: Position,
        prompt: Prompt,
        requestMultiline: boolean, blockMode: BlockMode, isCycling: boolean) {
    const currentLine = document.lineAt(position.line);
    const lineBeforeCursor = document.getText(new Range(currentLine.range.start, position));
    const restOfLine = document.getText(new Range(position, currentLine.range.end));

    const telemetryData = ghostTextTelemetry(document,
                                                position,
                                                prompt.prompt,
                                                lineBeforeCursor,
                                                restOfLine);
    // Add background about prompt creation
    telemetryData.properties.promptChoices = JSON.stringify(prompt.promptChoices,
        // stringify map -> object
        (key, value) => value instanceof Map ?
            Array.from(value.entries()).reduce((acc, [k, v]) => ({ ...acc, [k]: v }), {}) :
            value);
    telemetryData.measurements.promptComputeTimeMs = prompt.computeTimeMs;
    // Add requestMultiline information
    telemetryData.properties.isMultiline = JSON.stringify(requestMultiline);
    telemetryData.properties.blockMode = blockMode;
    telemetryData.properties.isCycling = JSON.stringify(isCycling);
    telemetry(ctx, "ghostText.issued", telemetryData);
    return telemetryData;
}
