import Ajv, { DefinedError } from "ajv";
import { Context } from "../../../lib/src/context";
import { telemetryRejected } from "../../../lib/src/ghostText/telemetry";
import { CopilotCompletionCache } from "../copilotCompletionCache";
import { ErrorCode, extractAjvErrors } from "../rpc";
import { MethodResult } from "./methods";

export type Params = {
    uuids: string[]
}

const paramsSchema = {
    type: 'object',
    required: ['uuids'],
    properties: {
        uuids: {
            type: 'array',
            items: {
                type: 'string'
            }
        }
    }
}

export type Response = "OK";


const ajv = new Ajv();
const _validParams = ajv.compile(paramsSchema);
function validParams(candidate: unknown): candidate is Params {
  return _validParams(candidate);
}

export async function notifyRejected(ctx: Context, params: unknown): Promise<MethodResult<Response>> {
    if(validParams(params)){
        let cache = ctx.get(CopilotCompletionCache)
        for (const uuid of params.uuids) {
            let completion = cache.get(uuid);
            if (completion) {
                telemetryRejected(ctx, "ghostText", completion.telemetry);
                //We don't need to keep the completion around anymore
                cache.deleteKey(uuid);
            }
        }
        return ["OK", null];
    } else {
        const errorMessages = extractAjvErrors(_validParams.errors as DefinedError[]);
        return [null, {
        code: ErrorCode.InvalidParams,
        message: 'Invalid params: ' + errorMessages.join(';')
        }];
    }
}