import { DocumentInfo, getPrompt } from '../../lib/src/promptLibProxy';
import { NeighboringTabsOption } from '../../prompt/src/prompt';
import { PromptChoices } from '@github/copilot-promptlib/dist/src/wishlist';
import { Context } from './context';


// The minimal cursor offset before we offer a completion
export const CompletionMinOffset = 10;

export interface Prompt {
    type: "prompt",
    prompt: string,
    promptChoices: PromptChoices,
    trailingWs: string,
    computeTimeMs: number,
}

export interface ContextTooShort {
    type: "contextTooShort",
}
export const _contextTooShort: ContextTooShort = { type: "contextTooShort" };
export type PromptResponse = Prompt | ContextTooShort
type OpenFileGetter = (filePath: string | undefined, languageId: string) => DocumentInfo[]

export type PromptBuilderCustomization = {
    getOpenFiles: OpenFileGetter | undefined
    getSolutionLength: (ctx: Context) => number
    getExperimentGroup: (ctx: Context) => string
}

async function getPromptForSource(ctx: Context, source: string, offset: number, filePath: string | undefined, relativePath: string | undefined, languageId: string, customizations: PromptBuilderCustomization) {
    let openFiles: DocumentInfo[] = [];

    if (!process.env.IS_AGENT && customizations.getOpenFiles) {
        openFiles = customizations.getOpenFiles(filePath, languageId)
    }
    const docInfo = {
        source,
        offset,
        path: filePath,
        relativePath,
        languageId,
        };
    const maxPromptLength = 2048 - customizations.getSolutionLength(ctx);
    const experimentGroup = customizations.getExperimentGroup(ctx);
    let neighboringTabs : NeighboringTabsOption | undefined;
    switch (experimentGroup) {
        case 'control:include_none': neighboringTabs = NeighboringTabsOption.None; break;
        case 'treatment:include_conservatively': neighboringTabs = NeighboringTabsOption.Conservative; break;
        case 'treatment:include_medium': neighboringTabs = NeighboringTabsOption.Medium; break;
        case 'treatment:include_eagerly': neighboringTabs = NeighboringTabsOption.Eager; break;
        case 'treatment:include_eagerly_but_little': neighboringTabs = NeighboringTabsOption.EagerButLittle; break;
    }
    const promptInfo = await getPrompt(docInfo, { maxPromptLength, neighboringTabs }, openFiles);
    if (promptInfo.suffix.length > 0 || promptInfo.suffixLength > 0) {
        throw new Error("Prompt suffixes are not yet supported");
    }
    return promptInfo;
}

/** Record trailing whitespace, and trim it from prompt if the last line is only whitespace */
export function trimLastLine(source: string): [string, string] {
    const lines = source.split("\n");
    const lastLine = lines[lines.length - 1];
    const extraSpace: number = lastLine.length - lastLine.trimRight().length;
    const promptTrim = source.slice(0, source.length - extraSpace);
    const trailingWs = source.substr(promptTrim.length);
    const resPrompt = lastLine.length == extraSpace ? promptTrim : source;
    return [resPrompt, trailingWs];
}

export async function extractPromptForSource(ctx: Context, source: string, offset: number, filePath: string | undefined, relativePath: string | undefined, languageId: string, customizations: PromptBuilderCustomization): Promise<PromptResponse> {
    if (offset < CompletionMinOffset) {
        // Too short context
        return _contextTooShort;
    }
    const startTime = Date.now();

    const { prefix, promptChoices } = await getPromptForSource(ctx, source, offset, filePath, relativePath, languageId, customizations);
    const [resPrompt, trailingWs] = trimLastLine(prefix);

    const endTime = Date.now();

    return { type: "prompt", prompt: resPrompt, trailingWs: trailingWs, promptChoices, computeTimeMs: endTime - startTime };
}