import { LineEndingOptions, PromptInfo } from "./prompt";
import { tokenLength } from "./tokenizer";

export enum PromptElementKind{
    BeforeCursor="BeforeCursor",
    AfterCursor="AfterCursor",
    SimilarFile="SimilarFile",
    ImportedFile="ImportedFile",
    LanguageMarker="LanguageMarker",
    PathMarker="PathMarker",
}

interface PromptElement {
    id: number;
    kind: PromptElementKind;
    priority: number;
    text: string;
    tokens: number;
    requires: PromptElement[]; // Elements that must have been selected before this one
    excludes: PromptElement[]; // Elements that will be skipped if this one is already selected
}

/**
 * Helper: given a list of indexed items and a target index, return an
 * item of the list with the smallest index that is greater than the target.
 */
function getMinimalGreater<T extends {index: number}>(items: T[], targetIndex: number): T | undefined {
    let bestIndex: number = Infinity;
    let best: T | undefined = undefined;
    for (const elem of items) {
        if (elem.index > targetIndex && elem.index < bestIndex) {
            best = elem;
            bestIndex = elem.index;
        }
    }
    return best;
}

export class PromptChoices {
    used: Map<PromptElementKind, number> = new Map<PromptElementKind, number>();
    unused: Map<PromptElementKind, number> = new Map<PromptElementKind, number>();

    /**
     * Register the decision to use a certain element in the prompt
     * @param element The element
     */
    markUsed(element: PromptElement): void {
        this.used.set(element.kind, (this.used.get(element.kind) || 0) + element.tokens);
    }

    /**
     * Undo the registration
     * @param element The element
     */
    undoMarkUsed(element: PromptElement) {
        this.used.set(element.kind, (this.used.get(element.kind) || 0) - element.tokens);
    }

     /**
      * Register the decision against using a certain element in the prompt
      * @param element The element
      */
    markUnused(element: PromptElement): void {
        this.unused.set(element.kind, (this.used.get(element.kind) || 0) + element.tokens);
    }
}


export class PromptWishlist {
    private content: PromptElement[] = [];
    lineEndingOption: LineEndingOptions;

    /**
     * An object to keep track of a list of desired prompt elements,
     * and assemble the prompt text from them.
     * @param lineEndingOption The line ending option to use
     */
    constructor(lineEndingOption: LineEndingOptions) {
        this.lineEndingOption = lineEndingOption;
    }

    getContent(): PromptElement[] {
        return [...this.content];
    }

    private convertLineEndings(text : string) {
        if (this.lineEndingOption === LineEndingOptions.ConvertToUnix) {
            text = text.replace(/\r\n/g, "\n").replace(/\r/g, "\n");
        }
        return text;
    }

    /**
     * Create a new {@link PromptElement} and add it to the wishlist
     * @param text The content of the element
     * @param kind The {@link PromptElementKind} each line will have.
     * @param priority A number representing the priority (larger means higher).
     * Priorities can be managed with a {@link Priorities} object.
     * @param tokens The number of tokens used by the element if tokenzied standalone;
     * will be computed if not supplied.
     */
    append(text: string, kind: PromptElementKind, priority: number, tokens: number = tokenLength(text)) : number {
        text = this.convertLineEndings(text);
        // make new id
        const id = this.content.length;
        this.content.push({id, text, kind, priority, tokens, requires: [], excludes: []});
        return id;
    }

    /**
     * Append each line of the text as {@link PromptElement} to the wishlist,
     * such that earlier lines depend on later ones.
     * @param text The content of the text
     * @param kind The {@link PromptElementKind} each line will have.
     * @param priority A number representing the priority (larger means higher) all lines will have.
     * Since equal priorities are tiebreaked by the order of the lines,
     * later lines will have a better chance to get into the prompt.
     * Priorities can be managed with a {@link Priorities} object.
     */
    appendLineForLine(text: string, kind: PromptElementKind, priority: number) : number[] {
        text = this.convertLineEndings(text);
        const rawLines = text.split("\n");
        // make sure the lines are "\n"-ended
        for (let i = 0; i < rawLines.length - 1; i++) {
            rawLines[i] += "\n";
        }
        const lines: string[] = [];
        rawLines.forEach((line, i) => {
            if (line === "\n"
                    && lines.length > 0
                    && !lines[lines.length - 1].endsWith("\n\n")) {
                lines[lines.length-1] += "\n";
            } else {
                lines.push(line);
            }
        });
        const returns: number[] = [];
        lines.forEach((line, i) => {
            if (line !== "") {
                // note that is always true for i < lines.length - 1
                returns.push(this.append(line, kind, priority));
                // let earlier lines depend on later ones
                if (i > 0) {
                    this.content[this.content.length - 2].requires = [this.content[this.content.length - 1]];
                }
            }
        });
        return returns;
    }

    /**
     * Adds a dependency of the first to the second element,
     * addressed by ID
     */
    require(dependentId: number, dependeeId: number) {
        const dependent = this.content.find(e => e.id === dependentId);
        const dependee = this.content.find(e => e.id === dependeeId);
        if (dependent && dependee) {
            dependent.requires.push(dependee);
        }
    }

    /**
     * Adds an exclusion:
     * if the first element is present, the second element won't be added anymore
     * addressed by ID
     */
    exclude(excludingId : number, excludedId: number) {
        const excluding = this.content.find(e => e.id === excludingId);
        const excluded = this.content.find(e => e.id === excludedId);
        if (excluding && excluded) {
            excluding.excludes.push(excluded);
        }
    }

    /**
     * Return a PromptInfo describing the prompt which _fulfills_ the wishlist:
     *
     * That means it has the following properties:
     * 1. the token length does not exceed maxPromptLength
     * 2. the order of the elements is as described in the wishlist
     * 3. pairs of elements such that the higher priority one excludes the lower will not both be selected
     * 4. elements that depend on another element will only be selected if the other one has higher priority and is selected
     *
     * Under all such subsets of the wishlist, it is maximal in the ordering where
     * set A < set B if there is an element e such that
     * * e in B and not in A
     * * B and A do not differ in elements of higher priority than e
     * * B and A do not differ in elements of equal priority but later position in the wishlist than e
     *
     * Implementation note: the condition in 4 that the dependee has higher priority is owing
     * to the algorithm implementing the wish fulfillment and may either be changed, or
     * we might remove the possibility to depend on a lower priority element altogether.
     *
     * @param maxPromptLength The maximum allowed prompt length in tokens
     * @returns A {@link PromptInfo} describing the prompt arrived at following the rules given above
     */
    fulfill(maxPromptLength: number) : PromptInfo {
        // keep a tally of the choices made
        const tallyOfChoices = new PromptChoices();

        // to avoid ties, move the priority of tied elements

        // want to add the highest priorities first,
        // but the final text should be in the order of the array
        // to keep track of that, add an index to each element of content
        const indexedContent = this.content.map((e, i) => { return {element: e, index: i};});


        // sorted by priority -- highest first, in case of a tie: latest first
        indexedContent.sort((a, b) => {
            if (a.element.priority === b.element.priority) {
                return b.index - a.index;
            }
            return b.element.priority - a.element.priority;
        });

        const idsThatHaveAlreadyBeenAdded: Set<number> = new Set<number>();
        const idsConflictingWithAlreadyAddedIds: Set<number> = new Set<number>();
        let budgetBreakingElement: {element: PromptElement, index: number} | undefined; // use this to include the first element that breaks the budget
        const remainingContent: {element: PromptElement, index: number}[] = [];
        let remainingBudget = maxPromptLength;
        indexedContent.forEach(e => {
            const element = e.element;
            const index = e.index;
            // we need to have budget, meet the requirements and have not
            // excluded the element
            if (remainingBudget >= 0
                    && (remainingBudget > 0 || budgetBreakingElement === undefined)
                    && element.requires.every(r => idsThatHaveAlreadyBeenAdded.has(r.id))
                    && !(idsConflictingWithAlreadyAddedIds.has(element.id))) {
                let budgetUse = element.tokens;
                // taking care of a bizarre edge case: double new line is a single token
                // _except_ if the following line starts with non-whitespace
                const probableNextElem = getMinimalGreater(remainingContent, index)?.element;
                if (element.text.endsWith("\n\n")
                        && probableNextElem
                        && !probableNextElem.text.match(/^\s/)) {
                    budgetUse++;
                }
                if (remainingBudget >= budgetUse){
                    remainingBudget -= budgetUse;
                    idsThatHaveAlreadyBeenAdded.add(element.id);
                    element.excludes.forEach(e => idsConflictingWithAlreadyAddedIds.add(e.id));
                    tallyOfChoices.markUsed(element);
                    remainingContent.push(e);
                } else {
                    // remember the element that broke the budget -- we may try whether it can still be included
                    budgetBreakingElement = budgetBreakingElement ?? e;
                }
            } else {
                tallyOfChoices.markUnused(element);
            }
        });

        // The budgeting logic for indexedContent is an approximation that can be
        // off slightly if the wishlist's order is very different from its priorities.
        // This may be due to:
        // * partial lines added together
        // * double new lines being a single token iff the next line does not start with whitespace
        //
        // We need to make sure that on no account can the prompt be too long.
        // Also, we want to test whether one more element would still fit.

        // Check that we do not go over:
        remainingContent.sort((a, b) => a.index - b.index);
        let prompt = remainingContent.reduce((a, b) => a + b.element.text, "");
        let promptLength = tokenLength(prompt);
        while (promptLength > maxPromptLength) {
            // take the least priority element and remove it after all
            remainingContent.sort((a, b) => {
                // Sort by least priority last, then by lowest index last
                if (b.element.priority === a.element.priority) {
                    return b.index - a.index;
                } else {
                    return b.element.priority - a.element.priority;
                }});
            const removeAfterAll = remainingContent.pop();
            if (removeAfterAll) {
                tallyOfChoices.undoMarkUsed(removeAfterAll.element);
                tallyOfChoices.markUnused(removeAfterAll.element);
                // Do not want the headaches that come with removing something
                // and adding it back again
                budgetBreakingElement = undefined;
            }
            remainingContent.sort((a, b) => a.index - b.index);
            prompt = remainingContent.reduce((a, b) => a + b.element.text, "");
            promptLength = tokenLength(prompt);
        }

        // Conversely, check whether we can get in more content
        // copy the remainingContent:
        const extendedContent = [...remainingContent];
        if (budgetBreakingElement !== undefined) {
            extendedContent.push(budgetBreakingElement);
            extendedContent.sort((a, b) => a.index - b.index);
            const prompt = extendedContent.reduce((a, b) => a + b.element.text, "");
            const promptLength = tokenLength(prompt);
            if (promptLength <= maxPromptLength) {
                // we can fit more content
                tallyOfChoices.markUsed(budgetBreakingElement.element);
                return {
                    prefix: prompt,
                    suffix: "",
                    prefixLength: promptLength,
                    suffixLength: 0,
                    promptChoices: tallyOfChoices,
                };
            } else {
                // we can't use it
                tallyOfChoices.markUnused(budgetBreakingElement.element);
            }
        }
        return {
            prefix: prompt,
            suffix: "",
            prefixLength: promptLength,
            suffixLength: 0,
            promptChoices: tallyOfChoices,
        };
    }
}

/**
 * A class to keep track of the choices made in a prompt
 * Implementation note:
 * This is fine for now, but repeated calls to justAbove, justBelow, etc.
 * will run into precision problems for >4000 or so priorities.
 */
export class Priorities {
    registeredPriorities = [0, 1];
    static TOP = 1;
    static BOTTOM = 0;
    /**
     * Register a new priority
     * @param priority The numerical value
     * @returns
     */
    register(priority: number){
        if (priority > Priorities.TOP || priority < Priorities.BOTTOM){
            throw new Error("Priority must be between 0 and 1");
        }
        this.registeredPriorities.push(priority);
        return priority;
    }

    /**
     * Registers a new priority above the given priorities,
     * but not above any other registered priority
     * @param priorities
     * @returns
     */
    justAbove(...priorities: number[]) : number {
        const priority = Math.max(...priorities);
        const nearestNeighbor = Math.min(...this.registeredPriorities.filter(p => p > priority));
        return this.register((nearestNeighbor + priority) / 2);
    }

    /**
     * Registers a new priority below the given priorities,
     * but not below any other registered priority
     * @param priorities
     * @returns
     */
    justBelow(...priorities: number[]) : number {
        const priority = Math.min(...priorities);
        const nearestNeighbor = Math.max(...this.registeredPriorities.filter(p => p < priority));
        return this.register((nearestNeighbor + priority) / 2);
    }

    /**
     * Verifies that the two priorities are adjacent in the list of priorities,
     * and returns one in the middle.
     */
    between(lower: number, higher: number) : number {
        if (this.registeredPriorities.some(p => p > lower && p < higher) ||
            !(this.registeredPriorities.includes(lower) && this.registeredPriorities.includes(higher))) {
                throw new Error("Priorities must be adjacent in the list of priorities");
            }
        return this.register((lower + higher) / 2);
    }
}