
import { ErrorCode, extractAjvErrors } from '../rpc';
import { MethodResult } from './methods';
import Ajv, { DefinedError } from 'ajv';
import { AuthStatus, AuthManager } from '../auth/manager';
import { Context } from '../../../lib/src/context';

export type Params = {
    options?: {}
};

const paramsSchema = {
    type: 'object',
    properties: {
      options: {
          type: 'object',
          required: [],
          properties: {
          }
        },
      }
};

export type Result = AuthStatus;

const ajv = new Ajv();
const _validParams = ajv.compile(paramsSchema);
function validParams(candidate: unknown): candidate is Params {
  return _validParams(candidate);
}

/**
 * The `signOut` method should be called if the user wants to sign out from GitHub and hence stop using
 * Copilot for now.
 *
 * The result will be an `AuthStatus` object, most likely `NotSignedIn`.
 */
export default async function handleSignOut(ctx: Context, params: unknown): Promise<MethodResult<Result>> {
    if (validParams(params)) {
        await ctx.get(AuthManager).deleteAuthRecord();
        const newStatus = await ctx.get(AuthManager).checkAndUpdateStatus(ctx);
        return [newStatus, null];
    } else {
          const errorMessages = extractAjvErrors(_validParams.errors as DefinedError[]);
          return [null, {
            code: ErrorCode.InvalidParams,
            message: 'Invalid params: ' + errorMessages.join(';')
        }];
    }
}
