/** Type for infering inner type of the Promise */
type Awaited<T> = T extends PromiseLike<infer U> ? U : T

/** Debounce function supporting debouncing of async functions */
export function debouncePromise<T extends (...args: any[]) => Promise<any>>(ms: number, callback: T): (...args: Parameters<T>) => Promise<Awaited<ReturnType<T>>> {
    let timer: NodeJS.Timeout | undefined;

    return (...args: Parameters<T>) => {
        if (timer) {
            clearTimeout(timer);
        }
        return new Promise<Awaited<ReturnType<T>>>((resolve) => {
            timer = setTimeout(async() => {
                const returnValue = await (callback(...args) as ReturnType<T>);
                resolve(returnValue);
            }, ms);
        });
    };
}

/** Debounce function for sync functions */
export function debounce<T extends (...args: any[]) => any>(ms: number, callback: T): (...args: Parameters<T>) => Promise<ReturnType<T>> {
    let timer: NodeJS.Timeout | undefined;

    return (...args: Parameters<T>) => {
        if (timer) {
            clearTimeout(timer);
        }
        return new Promise<ReturnType<T>>((resolve) => {
            timer = setTimeout(() => {
                const returnValue = (callback(...args) as ReturnType<T>);
                resolve(returnValue);
            }, ms);
        });
    };
}