import Ajv, { DefinedError } from 'ajv';
import ajvErrors from 'ajv-errors';
import { Context } from '../../lib/src/context';
import { MethodHandlers } from './methods/methods';

export type RpcMessage = {
  jsonrpc: '2.0',
  id: number;
  method: string;
  params: {} | [];
};

// NOTE: manually keeping in sync with the above type instead of using
// `JSONSchemaType` because (a) it can't support the `{} | []` union type and
// (b) it causes massive perf issues with Typescript, particularly with the
// VSCode integration. See
// <https://github.com/microsoft/TypeScript/issues/44851#issuecomment-890246966>
// for more info
const rpcMessageSchema/*: JSONSchemaType<RpcMessage>*/ = {
  type: 'object',
  properties: {
    jsonrpc: { type: 'string', const: '2.0' },
    id: { type: 'number' },
    method: { type: 'string' },
    params: {
      anyOf: [
        { type: 'object', required: [] },
        { type: 'array' }
      ]
    }
  },
  required: ['jsonrpc', 'id', 'method', 'params'],
  errorMessage: {
    properties: {
      jsonrpc: `jsonrpc must be '2.0'`
    }
  }
};
const ajv = new Ajv({
  // option required by ajv-errors
  allErrors: true
});
ajvErrors(ajv);

const _isRpcMessage = ajv.compile(rpcMessageSchema);
// TODO: is it possible to tell TS that _isRpcMessage should be treated as a
// type guard instead of wrapping it?
function isRpcMessage(candidate: unknown): candidate is RpcMessage {
  return _isRpcMessage(candidate);
}

export type RpcResponseResult<R> = {
  jsonrpc: '2.0',
  id: number,
  result: R,
};

export type RpcResponseError = {
  jsonrpc: '2.0',
  id: number | null,
  error: RpcError,
};

export type RpcResponse<R> = RpcResponseResult<R> | RpcResponseError;
export function isErrorResponse(response: RpcResponse<unknown>): response is RpcResponseError {
  return 'error' in response;
}

export type RpcError = {
  code: number,
  message: string,
  data?: unknown,
};

export enum ErrorCode {
  // From <https://www.jsonrpc.org/specification#error_object>
  ParseError = -32700,
  InvalidRequest = -32600,
  MethodNotFound = -32601,
  InvalidParams = -32602,
  InternalError = -32603,

  // 0-999 are reserved for errors reported by the client.
  // 0-255 are normally used to report a POSIX exit code from the agent if it dies unexpectedly.
  // There's currently no standard for what to do for exit codes above 256, which are possible e.g. on Windows.

  // Our errors
  NoCopilotToken = 1000,
  DeviceFlowFailed = 1001,
};

export async function processMessage(ctx: Context, obj: any): Promise<RpcResponse<unknown>> {
  try {
    if (isRpcMessage(obj)) {
      const message: RpcMessage = obj;
      const id = message.id;
      const method = message.method;
      const handler = ctx.get(MethodHandlers).handlers.get(method);
      if (!handler) {
        return makeRpcResponseError(id, {
          code: ErrorCode.MethodNotFound,
          message: `Method not found: '${method}'`
        });
      }
      const [maybeResult, maybeErr] = await handler(ctx, message.params);
      if (maybeErr) {
        return makeRpcResponseError(id, maybeErr);
      } else {
        return makeRpcResponseResult(id, maybeResult);
      }
    } else {
      const errorMessages = extractAjvErrors(_isRpcMessage.errors as DefinedError[]);
      const id = typeof obj.id === 'number' ? obj.id : null;

      return makeRpcResponseError(id, {
        code: ErrorCode.InvalidRequest,
        message: `Invalid request: ${errorMessages.join('; ')}`
      });
    }
  } catch (err) {
    return makeRpcResponseError(lookForId(obj), {
      code: ErrorCode.InternalError,
      message: `Internal error: ${err}`,
      data: {
        // @ts-ignore
        stack: err.stack
      }
    });
  }
}


export async function processLineCatch(ctx: Context, line: string): Promise<string> {
  let obj;
  try {
    obj = JSON.parse(line);
    let response = await processMessage(ctx, obj);
    return JSON.stringify(response);
  } catch (maybeError: any) {
    if (maybeError instanceof Error && maybeError.name === 'SyntaxError') {
      return JSON.stringify(makeRpcResponseError(null, {
        code: ErrorCode.ParseError,
        message: `Parse error: ${maybeError}`
      }));
    }
    const error: RpcError = {
      code: ErrorCode.InternalError,
      message: `Internal error: ${maybeError.toString()}`
    };
    const response = makeErrorResponse(lookForId(obj), error);
    return JSON.stringify(response);
  };
}

export function rpcSend(response: RpcResponse<unknown>): void {
  rpcSendString(JSON.stringify(response));
}

export function rpcSendString(response: string): void {
  console.log(response);
}

export function makeRpcResponseError(id: number | null, error: RpcError): RpcResponseError {
  return {
    jsonrpc: '2.0',
    id,
    error
  };
}

export function makeRpcResponseResult<R>(id: number, result: R): RpcResponseResult<R> {
  return {
    jsonrpc: '2.0',
    id,
    result
  };
}

function makeErrorResponse(maybeId: unknown, err: RpcError): RpcResponse<unknown> {
  const response: RpcResponse<unknown> = {
    jsonrpc: '2.0',
    id: typeof maybeId === 'number' ? maybeId : null,
    error: err
  };

  return response;
}


export function lookForId(obj: any): number | null {
  try {
    if (typeof obj.id === 'number') {
      return obj.id;
    }
    return null;
  } catch (e) {
    return null;
  }
}

export function extractAjvErrors(errors: DefinedError[]): string[] {
  return errors.map(err => {
    // The instance path may be overly verbose for some top-level errors, but
    // it's critical for making sense of anything nested
    return `${err.instancePath} ${err.message}`;
  });
}

