import { DocumentInfo } from './prompt';

class FifoCache<T> {
    private keys: string[] = [];
    private cache: { [key: string]: T } = {};
    private size: number;
    constructor(size: number) {
        this.size = size;
    }
    put(key: string, value: T) {
        this.cache[key] = value;
        if (this.keys.length > this.size) {
            this.keys.push(key);
            const leavingKey = this.keys.shift() ?? "";
            delete this.cache[leavingKey];
        }
    }
    get(key: string): T | undefined {
        return this.cache[key];
    }
}

/**
 * For a number of documents (the neighboring tabs), 
 * associate to each document (as key)
 * the sequence b_1, ..., b_n, where 
 * b_i is the set of tokens in the ith window --
 * e.g. for window length 10, 
 * WINDOWED_TOKEN_SET_CACHE(doc)[0] 
 * holds the tokens in the first 10 lines of the document.
 */
const WINDOWED_TOKEN_SET_CACHE = new FifoCache<Set<string>[]>(20);

export interface ScoredSnippet {
    score: number;
    snippet: string;
    relativePath?: string;
}

/**
 * Returns the snippet from the object document
 * that is 
 * - most similar to the reference Document
 * - does not contain partial lines
 * - has at least windowLength non-stop words (or covers the entire object)
 * - is the shortest such snippet
 * together with their Jaccard score
 * 
 * @param objectDoc 
 * @param referenceDoc 
 * @param windowLength 
 */
export function findBestJaccardMatch(objectDoc: DocumentInfo, referenceDoc: DocumentInfo, windowLength: number):
    ScoredSnippet | undefined {
    if (objectDoc.source.length === 0 || referenceDoc.source.length === 0) {
        return undefined;
    }
    const stopsForLanguage = SPECIFIC_STOPS.get(referenceDoc.languageId) ?? GENERIC_STOPS;
    const referenceTokens = new Set<string>(splitIntoWords(referenceDoc.source).filter(x => !stopsForLanguage.has(x)));

    const lines = objectDoc.source.split('\n');

    const key = windowLength.toString() + ":" + objectDoc.source;
    const tokensInWindows = WINDOWED_TOKEN_SET_CACHE.get(key) ?? [];
    const needToComputeTokens = tokensInWindows.length == 0;
    const tokenizedLines = needToComputeTokens ?
        lines.map(line => new Set(splitIntoWords(line).filter(x => !stopsForLanguage.has(x)))) :
        [];

    // Compute the window with the best match
    let bestMatchStart = -1;
    let bestScore = 0;
    for (let startLine = 0; startLine == 0 || startLine < lines.length - windowLength; startLine++) {
        const endLine = Math.min(startLine + windowLength, lines.length);
        if (needToComputeTokens) {
            const tokensInWindow = new Set<string>();
            tokenizedLines.slice(startLine, endLine).forEach((x) => x.forEach(tokensInWindow.add, tokensInWindow));
            tokensInWindows.push(tokensInWindow);
        }
        // Now tokensInWindows[startLine] contains the tokens in the window, whether we just computed them or not
        const tokensInWindow = tokensInWindows[startLine];
        const score = computeScore(tokensInWindow, referenceTokens);
        if (score > bestScore) {
            bestScore = score;
            bestMatchStart = startLine;
        }
    }
    // If we didn't get the token sets from the cache, time to put them there!
    if (needToComputeTokens) {
        WINDOWED_TOKEN_SET_CACHE.put(key, tokensInWindows);
    }

    // return the best match
    if (bestMatchStart === -1) {
        return undefined;
    } else {
        const startLine = bestMatchStart;
        const endLine = Math.min(startLine + windowLength, lines.length);
        const snippet = lines.slice(startLine, endLine).join('\n');
        return {
            snippet,
            score: bestScore
        };
    }
}

/**
 * Compute the Jaccard metric of number of elements in the intersection
 * divided by number of elements in the union
 */
function computeScore(a: Set<string>, b: Set<string>) {
    const intersection = new Set();
    a.forEach(x => {
        if (b.has(x)) {
            intersection.add(x);
        }
    });
    return intersection.size / (a.size + b.size - intersection.size);
}

/**
 * Split by non-alphanumeric characters
 */
export function splitIntoWords(a: string): string[] {
    return a.split(/[^a-zA-Z0-9]/).filter(x => x.length > 0);
}

/**
 * Common English stop words (in particular relevant for comments)
 */
const ENGLISH_STOPS = new Set([
    // - pronouns
    "we", "our", "you", "it", "its", "they", "them", "their",
    "this", "that", "these", "those",
    // - verbs
    "is", "are", "was", "were", "be", "been", "being", "have", "has", "had", "having", "do", "does", "did", "doing",
    "can", "don", "t", "s", "will", "would", "should",
    // - wh-words
    "what", "which", "who", "when", "where", "why", "how",
    // - articles    
    "a", "an", "the",
    // - prepositions 
    "and", "or", "not", "no", "but", "because", "as", "until",
    "again", "further", "then", "once", "here", "there",
    "all", "any", "both", "each", "few", "more", "most", "other", "some", "such",
    "above", "below", "to", "during", "before", "after",
    "of", "at", "by", "about", "between", "into", "through",
    "from", "up", "down", "in", "out", "on", "off", "over", "under",
    "only", "own", "same", "so", "than", "too", "very", "just", "now"
]);

/**
 * A generic set of stops for any programming language
 */
const GENERIC_STOPS = new Set([
    // words that are common in programming languages
    "if", "then", "else", "for", "while", "with", "def", "function", "return", "TODO",
    "import", "try", "catch", "raise", "finally", "repeat",
    "switch", "case", "match", "assert",
    "continue", "break", "const",
    "class", "enum", "struct", "static",
    "new", "super", "this", "var",
    // words that are common in English comments: 
    ...ENGLISH_STOPS
]);

/**
 * Specific stops for certain languages
 * Note that ENGLISH_STOPS need to be added to this set if they are to be included
 */
const SPECIFIC_STOPS: Map<string, Set<string>> = new Map([
    // none yet
]);