import { window } from 'vscode';
import { ConfigKey, getConfig } from '../config';
import { Context } from '../context';

// Engine Urls

// exported for test
export const OPENAI_PROXY_HOST = "https://copilot-proxy.githubusercontent.com";

export const engineUrls: {[key: string]: string} = {
    "*":               "/v1/engines/copilot-codex",
};

// Config methods

// This method will return "" if no override is set, otherwise it is expected to return a valid url
function getOverrideProxyURL(ctx: Context): string {
    const overrideProxyUrl = getConfig<string>(ctx, ConfigKey.DebugOverrideProxyUrl);
    return overrideProxyUrl;
}

function _getLanguageConfig(obj: {[key: string]: string}, language?: string): any {
    if (language === undefined && !process.env.IS_AGENT) {
        const editor = window.activeTextEditor;
        language = editor && editor.document.languageId;
    }
    return (language && language in obj) ? obj[language] : obj["*"];
}

function _getLanguageConfigUrl(ctx: Context, obj: {[key: string]: string}, language?: string): string | undefined {
    // get the engine for the language
    const path = _getLanguageConfig(obj, language);
    if (!path) {
        return undefined;
    }

    let proxyUrl = getOverrideProxyURL(ctx);
    if (proxyUrl.length == 0) {
        proxyUrl = OPENAI_PROXY_HOST;
    }
    return `${proxyUrl}${path}`;
}

export function getEngineURL(ctx: Context): any {
    let language: string | undefined;
    if (!process.env.IS_AGENT) {
        const editor = window.activeTextEditor;
        language = editor?.document.languageId;
    }

    return _getLanguageConfigUrl(ctx, engineUrls, language);
}
