import * as path from 'path';
import * as Parser from 'web-tree-sitter';
import { Language, Query, QueryMatch, SyntaxNode, Tree } from 'web-tree-sitter';

export enum WASMLanguage {
    Python = "python",
    JavaScript = "javascript",
    TypeScript = "typescript",
    Go = "go",
    Ruby = "ruby",
};

/**
 * A position of a syntax-tree node, specified by a zero-based start offset and a zero-based,
 * exclusive end offset.
 */
export interface NodePosition {
    startIndex: number;
    endIndex: number;
}

const languageIdToWasmLanguageMapping: { [language: string]: WASMLanguage } = {
    "python":          WASMLanguage.Python,
    "javascript":      WASMLanguage.JavaScript,
    "javascriptreact": WASMLanguage.JavaScript,
    "jsx":             WASMLanguage.JavaScript,
    "typescript":      WASMLanguage.TypeScript,
    "typescriptreact": WASMLanguage.TypeScript,
    "go":              WASMLanguage.Go,
    "ruby":            WASMLanguage.Ruby,
};

export function isSupportedLanguageId(languageId: string): boolean {
    return languageId in languageIdToWasmLanguageMapping;
}

export function languageIdToWasmLanguage(languageId: string): WASMLanguage {
    if (!(languageId in languageIdToWasmLanguageMapping)) {
        throw new Error(`Unrecognized language: ${languageId}`);
    }
    return languageIdToWasmLanguageMapping[languageId];
}

/*
List of queries to run per language to find functions, as well as a cache
for parsed Query objects for each query.

We define named captures to be used by callers in a language-agnostic way:
- @function: entire function signature and body
- @docstring: optional docstring
- @body: optional function body

NOTE: use a [] match across function types to ensure we always match the
      outermost function in case of nested functions.
*/
const functionQuery: { [wasmLanguage in WASMLanguage]: [string, Query?][] } = {
    "python": [
        // `(function_definition)` is defined in python grammar:
        // https://github.com/tree-sitter/tree-sitter-python/blob/c4282ba411d990d313c5f8e7850bcaaf46fbf7da/grammar.js#L325-L338
        // docstring is represented in grammar as an optional `(initial expression_statement (string))`
        // at the start of the body block
        [`(function_definition body: (block
             (expression_statement (string))? @docstring) @body) @function`],
        // handle malformed defs - no trailing semicolon or no body
        [`(ERROR ("def" (identifier) (parameters))) @function`]
    ],
    "javascript": [
        // function patterns defined in javascript grammer:
        // https://github.com/tree-sitter/tree-sitter-javascript/blob/3d9fe9786ee74fa5067577f138e1a7129f80fb41/grammar.js#L595-L629
        // TODO: include `arrow_function` as well?
        [`[
            (function body: (statement_block) @body)
            (function_declaration body: (statement_block) @body)
            (generator_function body: (statement_block) @body)
            (generator_function_declaration body: (statement_block) @body)
            (method_definition body: (statement_block) @body)
          ] @function`]
    ],
    "typescript": [
        // function patterns defined in typescript grammer:
        // https://github.com/tree-sitter/tree-sitter-typescript/blob/2d1c7d5c10c33cb444d1781fa76f2936810afec4/common/define-grammar.js
        // which inherits from javascript, so just reuse those patterns
        [`[
            (function body: (statement_block) @body)
            (function_declaration body: (statement_block) @body)
            (generator_function body: (statement_block) @body)
            (generator_function_declaration body: (statement_block) @body)
            (method_definition body: (statement_block) @body)
          ] @function`]
    ],
    "go": [
        // function patterns defined in go grammer:
        // https://github.com/tree-sitter/tree-sitter-go/blob/b0c78230146705e867034e49a5ece20245b33490/grammar.js#L194-L209
        [`[
            (function_declaration body: (block) @body)
            (method_declaration body: (block) @body)
          ] @function`],
    ],
    "ruby": [
        // function patterns defined in ruby grammer:
        // https://github.com/tree-sitter/tree-sitter-ruby/blob/master/grammar.js
        // NOTE: Use a @params label for optional parameters to avoid capturing as
        //       part of @body if parameters are present.
        [`[
            (method name: (_) parameters: (method_parameters)? @params [(_)+ "end"] @body)
            (singleton_method name: (_) parameters: (method_parameters)? @params [(_)+ "end"] @body)
          ] @function`],
    ],
};

/** A call of the form `require(...)`. */
const requireCall = `(call_expression function: ((identifier) @req (#eq? @req "require")))`;

/** A call of the form `require(...)` appearing in a variable declarator. */
const declaratorWithRequire = `(variable_declarator value: ${requireCall})`;

/**
 * A CommonJS-style `require` import.
 *
 * Note that a declaration containing multiple `require`s is considered a single import.
 */
const commonJsImport = `
    (lexical_declaration ${declaratorWithRequire}+)
    (variable_declaration ${declaratorWithRequire}+)
`;

const importsQuery: { [wasmLanguage in WASMLanguage]: [string, Query?][] } = {
    "python": [
        // Since we only care about top level imports, we enforce that the parent node is "module"
        [`(module (future_import_statement) @import)`],
        [`(module (import_statement) @import)`],
        [`(module (import_from_statement) @import)`],
    ],
    "javascript": [
        // Since we only care about top level imports, we enforce that the parent node is "program"
        [`(program [ ${commonJsImport} ] @import)`],
        ['(program [ (import_statement) ] @import)']
    ],
    "typescript": [
        // Since we only care about top level imports, we enforce that the parent node is "program"
        [`(program [ ${commonJsImport} ] @import)`],
        ['(program [ (import_statement) (import_alias) ] @import)']
    ],
    "go": [
        // TODO: handle import statements in go
    ],
    "ruby": [
        // TODO: handle import statements in ruby
    ],
};

const exportsQuery: { [wasmLanguage in WASMLanguage]: [string, Query?][] } = {
    "python": [
        // TODO: handle exports in python
    ],
    "javascript": [
        [`(program (export_statement) @export)`],
    ],
    "typescript": [
        [`(program (export_statement) @export)`],
    ],
    "go": [
        // TODO: handle exports in go
    ],
    "ruby": [
        // TODO: handle exports in ruby
    ],
};

const globalVarsQuery: { [wasmLanguage in WASMLanguage]: [string, Query?][] } = {
    "python": [
        // Since we only care about top level global vars, we enforce that the parent node is "module"
        [`(module (global_statement) @globalVar)`],
        [`(module (expression_statement) @globalVar)`],
    ],
    "javascript": [
        // TODO: handle global vars in javascript
    ],
    "typescript": [
        // TODO: handle global vars in typescript
    ],
    "go": [
        // TODO: handle global vars in go
    ],
    "ruby": [
        // TODO: handle global vars in ruby
    ],
};

/**
 * TreeSitter node types corresponding to functions for the given language.
 */
const functionTypes: { [wasmLanguage in WASMLanguage]: Set<string> } = {
    "python": new Set([
        "function_definition",
    ]),
    "javascript": new Set([
        "function",
        "function_declaration",
        "generator_function",
        "generator_function_declaration",
        "method_definition",
        "arrow_function"
    ]),
    "typescript": new Set([
        "function",
        "function_declaration",
        "generator_function",
        "generator_function_declaration",
        "method_definition",
        "arrow_function"
    ]),
    "go": new Set([
        "function_declaration",
        "method_declaration"
    ]),
    "ruby": new Set([
        "method",
        "singleton_method"
    ]),
};

/**
 * TreeSitter node types corresponding to syntactic constructs that can have function declarations
 * as their immediate children.
 */
const isFunctionParent: { [wasmLanguage in WASMLanguage]: (nd: SyntaxNode) => boolean } = {
    "python": (nd) =>
        nd.type === "module" || nd.type === "block" && nd.parent?.type === "class_definition",
    "javascript": (nd) =>
        nd.type === "program" || nd.type === "class_body",
    "typescript": (nd) =>
        nd.type === "program" || nd.type === "class_body",
    "go": (nd) =>
        nd.type === "source_file",
    "ruby": (nd) =>
        nd.type === "program" || nd.type === "class"
};

const loadedLanguages = new Map<WASMLanguage, Language>();

async function loadWasmLanguage(language: WASMLanguage): Promise<Language> {
    await Parser.init();
    // construct a path that works both for the TypeScript source, which lives under `/src`, and for
    // the transpiled JavaScript, which lives under `/dist`
    const wasmFile = path.resolve(__dirname, '..', 'dist', `tree-sitter-${language}.wasm`);
    return Language.load(wasmFile);
}

export async function getLanguage(language: string): Promise<Language> {
    const wasmLanguage = languageIdToWasmLanguage(language);
    if (!loadedLanguages.has(wasmLanguage)) {
        const loadedLang = await loadWasmLanguage(wasmLanguage);
        loadedLanguages.set(wasmLanguage, loadedLang);
    }
    return loadedLanguages.get(wasmLanguage)!;
}

// This method returns a tree that the user needs to call `.delete()` before going out of scope.
export async function parseTree(language: string, source: string): Promise<Tree> {
    // `getLanguage` calls `Parser.init`, which needs to be called before `new Parser()` below
    let treeSitterLanguage = await getLanguage(language);
    const parser = new Parser();
    parser.setLanguage(treeSitterLanguage);
    const parsedTree = parser.parse(source);

    // Need to delete parser objects directly
    parser.delete();
    return parsedTree;
}

export async function parsesWithoutError(language: string, source: string): Promise<boolean> {
    const tree = await parseTree(language, source);
    const result = !tree.rootNode.hasError();
    tree.delete();
    return result;
}

export function getBlockCloseToken(language: string): string | null {
    const wasmLanguage = languageIdToWasmLanguage(language);
    switch (wasmLanguage) {
        case WASMLanguage.Python:
            return null;
        case WASMLanguage.JavaScript:
        case WASMLanguage.TypeScript:
        case WASMLanguage.Go:
            return "}";
        case WASMLanguage.Ruby:
            return "end";
    }
}

function innerQuery(queries: [string, Query?][], root: SyntaxNode): QueryMatch[] {
        const matches = [];
        for (const query of queries) {
            // parse and cache query if this is the first time we've used it
            if (!query[1]) {
                const lang = root.tree.getLanguage() as Language;
                // cache parsed query object
                query[1] = lang.query(query[0]);
            }
            matches.push(...query[1].matches(root));
        }
        return matches;
}

export function queryFunctions(language: string, root: SyntaxNode): QueryMatch[] {
    const queries = functionQuery[languageIdToWasmLanguage(language)];
    return innerQuery(queries, root);
}

/**
 * A list of all top-level imports in the given tree.
 *
 * Note that imports are _not_ guaranteed to be in the same order as the source code.
 */
export function queryImports(language: string, root: SyntaxNode): QueryMatch[] {
    const queries = importsQuery[languageIdToWasmLanguage(language)];
    return innerQuery(queries, root);
}

export function queryExports(language: string, root: SyntaxNode): QueryMatch[] {
    const queries = exportsQuery[languageIdToWasmLanguage(language)];
    return innerQuery(queries, root);
}

export function queryGlobalVars(language: string, root: SyntaxNode): QueryMatch[] {
    const queries = globalVarsQuery[languageIdToWasmLanguage(language)];
    return innerQuery(queries, root);
}

const docstringQuery: [string, Query?] = [`[
    (class_definition (block (expression_statement (string))))
    (function_definition (block (expression_statement (string))))
]`];

export function queryPythonIsDocstring(blockNode: SyntaxNode): boolean {
    return innerQuery([docstringQuery], blockNode).length == 1;
}

/**
 * Find the closest ancestor node of `nd` that may have function declarations as sibling nodes.
 */
export function getAncestorWithSiblingFunctions(language: string, nd: SyntaxNode): SyntaxNode | null {
    const check = isFunctionParent[languageIdToWasmLanguage(language)];
    while (nd.parent) {
        if (check(nd.parent))
            return nd;
        nd = nd.parent;
    }
    return nd.parent ? nd : null;
}

/**
 * Check if `nd` is a function.
 *
 * Note that for a JavaScript declaration like
 *
 * ```js
 * var f = function g() {}
 * ```
 *
 * only the node corresponding to the function expression `function g() {}` is considered to be
 * a function, not the entire declaration.
 *
 * Conversely, the declaration is considered a function definition (see below), but the function
 * expression is not.
 */
export function isFunction(language: string, nd: SyntaxNode): boolean {
    return functionTypes[languageIdToWasmLanguage(language)].has(nd.type);
}

/**
 * Check if `nd` is a function definition.
 *
 * For languages other than JavaScript, this is the same as checking whether `nd` is a function.
 * For JavaScript, function expressions are _not_ considered function definitions, but declarations
 * and assignments assigning a function expression to a variable are.
 */
 export function isFunctionDefinition(language: string, nd: SyntaxNode): boolean {
    switch(languageIdToWasmLanguage(language)) {
    case WASMLanguage.Python:
    case WASMLanguage.Go:
    case WASMLanguage.Ruby:
        return isFunction(language, nd);
    case WASMLanguage.JavaScript:
    case WASMLanguage.TypeScript:
        // either it is a stand-alone function declaration
        if (nd.type === "function_declaration" ||
            nd.type === "generator_function_declaration" ||
            nd.type === "method_definition")
            return true;

        // or a declaration of a function-valued variable
        if (nd.type === "lexical_declaration" || nd.type === "variable_declaration") {
            // declarations with multiple declarators (`var x = ..., y = ...`) are unlikely to
            // involve functions in practice, so we make our lives easier and short-circuit
            if (nd.namedChildCount > 1)
                return false;
            let declarator = nd.namedChild(0);
            // this should never be null, but we check anyway to be safe
            if (declarator == null)
                return false;
            let init = declarator.namedChild(1);
            return init !== null && isFunction(language, init);
        }

        // or an assignment to a function-valued variable
        if (nd.type === "expression_statement") {
            let expr = nd.namedChild(0);
            if (expr?.type === "assignment_expression") {
                let rhs = expr.namedChild(1);
                return rhs !== null && isFunction(language, rhs);
            }
        }

        return false;
    }
}

/**
 * Get the first comment in a run of comments preceding `nd`, if any.
 *
 * That is, if `nd` is preceded by a single comment, return that comment. If it is
 * preceded by a sequence of more than one comments (without any intervening non-comment
 * nodes or blank lines), return the first comments in that sequence. Otherwise return `null`.
 *
 * Note that all comments are treated equally; in particular, for JavaScript, no distinction
 * is made between block comments and line comments.
 */
export function getFirstPrecedingComment(nd: SyntaxNode) : SyntaxNode | null {
    // starting from `nd`, walk backwards until we find a node that is not preceded by a comment
    let cur = nd;
    while (cur.previousSibling?.type === 'comment') {
        let prev = cur.previousSibling;
        // stop if there is an intervening blank line
        if (prev.endPosition.row < cur.startPosition.row - 1)
            break;
        cur = prev;
    }

    // if that node is itself a comment, it is the first one in a run of comments preceding `nd`
    if (cur?.type === 'comment')
        return cur;
    // otherwise it must be `nd`, so there aren't any comments preceding `nd`
    return null;
}

/**
 * Get the positions of all function nodes in the given piece of source code.
 */
export async function getFunctionPositions(language: string, source: string) : Promise<NodePosition[]> {
    const tree = await parseTree(language, source);
    const results = queryFunctions(language, tree.rootNode);
    return results.map((res) => {
        const fn = res.captures.find(c => c.name === 'function')!.node;
        return {
            startIndex: fn.startIndex,
            endIndex: fn.endIndex,
        };
    });
}
