/**
 * This file is about the situation where
 * we have a completion from the model,
 * but refrain from showing it to the user by default.
 * That may be because we suspect it to be
 * wrong, useless, or distracting.
 */

import { ghostTextDisplayLog1pcompCharLenParameter,
    ghostTextDisplayInterceptParameter,
    ghostTextDisplayLanguageParameters,
    ghostTextDisplayMeanAlternativeLogProbParameter,
    ghostTextDisplayMeanLogProbParameter,
    ghostTextDisplayQuantiles } from "./mlConstants";
import { TelemetryData } from "./telemetry";
import { Logger, LogLevel } from './logger';
import { Context } from "./context";

const restraintLogger = new Logger(LogLevel.INFO, "restraint");

// Some maths functionality

/**
 * Link functions are invertible monotone functions with domain [0, 1])
 * For any p in [0, 1], unlink(link(p)) = p
 * For any x in the codomain, unlink(x) must be in [0, 1] and link(unlink(x)) = x
 */
interface LinkFunction {
    link: (p: number) => number;
    unlink: (x: number) => number;
}

const Logit: LinkFunction = {
    link: (x: number) => Math.exp(x) / (1 + Math.exp(x)),
    unlink: (p: number) => Math.log(p / (1 - p))
};

/**
 * Linear interpolation based on data points of a monotonically increasing function.
 * @param x0 The input x-value
 * @param points Data points (x,y) of a monotonically increasing function
 * @returns An approximation of the y-value corresponding to `x0`
 */
function linearInterpolation(x0: number, points: Map<number, number>): number {
    const x_after  = Math.min(...Array.from(points.keys()).filter(x => x >= x0));
    const x_before = Math.max(...Array.from(points.keys()).filter(x => x  < x0));
    const y_after = points.get(x_after) as number;
    const y_before = points.get(x_before) as number;
    return y_before + (y_after - y_before) * (x0 - x_before)/(x_after - x_before);
}

// Defining logistic regression models

class Regressor {
    name: string;
    coefficient: number;
    transformation: (x: number) => number;

    constructor(name: string, coefficient: number, transformation?: (x: number) => number){
        this.name = name;
        this.coefficient = coefficient;
        // identity as default
        this.transformation = transformation? transformation: (x): number => x;
    }

    public contribution(value: number): number {
        return this.coefficient * this.transformation(value);
    }
}

class LogisticRegression {
    intercept: number;
    coefficients: Regressor[];
    logitsToQuantiles: Map<number, number>;
    link: LinkFunction = Logit;

    constructor(intercept: number, coefficients: Regressor[], quantiles?:  { [key: number]: number }) {
        this.intercept = intercept;
        this.coefficients = coefficients;
        this.logitsToQuantiles = new Map();
        this.logitsToQuantiles.set(0,0);
        this.logitsToQuantiles.set(1,1);
        // add the quantiles if present
        if (quantiles) {
            for (const key in quantiles) {
                this.logitsToQuantiles.set(quantiles[key], Number(key));
            }
        }
    }

    public predict(ctx: Context, values: { [key: string]: number }): number {
        let sum = this.intercept;
        // loop through the key value pairs in this.coefficients
        // and calculate the sum of the coefficients
        // for each pair
        for (const regressor of this.coefficients) {
            const value = values[regressor.name];
            if (value === undefined) {
                restraintLogger.error(ctx, `No value found for ${regressor.name} -- only got ${JSON.stringify(values)}`);
                return NaN;
            } else {
                sum += regressor.contribution(value);
            }
        }
        return this.link.link(sum);
    }

    public quantile(ctx: Context, values: { [key: string]: number }): number {
        const logit = this.predict(ctx, values);
        return linearInterpolation(logit, this.logitsToQuantiles);
    }
}

const ghostTextRetentionModel =  new LogisticRegression(ghostTextDisplayInterceptParameter, [
        new Regressor("compCharLen", ghostTextDisplayLog1pcompCharLenParameter, (x) => Math.log(1+x)),
        new Regressor("meanLogProb", ghostTextDisplayMeanLogProbParameter),
        new Regressor("meanAlternativeLogProb", ghostTextDisplayMeanAlternativeLogProbParameter)]
        .concat(
            Object.entries(ghostTextDisplayLanguageParameters).map<Regressor>(
                (value: [string, number])=> new Regressor(value[0], value[1])
            )),
     ghostTextDisplayQuantiles);

// Answering the question whether items should be displayed

/**
 * Return a "higher-is-better" score
 * representing the confidence that the ghostText suggestion
 * will be retained, from 1 (certainly) down to 0 (certainly not).
 */
export function ghostTextScoreConfidence(ctx: Context, telemetryData: TelemetryData): number {
    const values = { ...telemetryData.measurements};
    // add language presence -- iterate over all fields of the languagaParameters object
    Object.keys(ghostTextDisplayLanguageParameters).forEach(lang => {
        values[lang] = telemetryData.properties["customDimensions.languageId"] == lang ? 1 : 0;
    });
    return ghostTextRetentionModel.predict(ctx, values);
}

/**
 * Return a "higher-is-better" score
 * representing that this solution is expected to as good or better than
 * how many others, from 1 (better than all) down to 0 (better than none).
 */
 export function ghostTextScoreQuantile(ctx: Context, telemetryData: TelemetryData): number {
    const values = { ...telemetryData.measurements};
    // add language presence -- iterate over all fields of the languagaParameters object
    Object.keys(ghostTextDisplayLanguageParameters).forEach(lang => {
        values[lang] = telemetryData.properties["customDimensions.languageId"] == lang ? 1 : 0;
    });
    return ghostTextRetentionModel.quantile(ctx, values);
}