import { ErrorCode, extractAjvErrors } from '../rpc';
import { MethodResult } from './methods';
import Ajv, { DefinedError } from 'ajv';
import { AuthStatus, AuthManager } from '../auth/manager';
import { Context } from '../../../lib/src/context';

export type Params = {
    options?: {
        /**
         * If `true` then only conduct partial checks that can be run locally.
         *
         * If `false` then include any steps that require the network.
         *
         * Defaults to `false`.
         */
         localChecksOnly?: boolean;
    }
};

const paramsSchema = {
    type: 'object',
    properties: {
      options: {
          type: 'object',
          required: [],
          properties: {
              localChecksOnly: { type: 'boolean' },
          }
        },
      }
};

export type Result = AuthStatus;

const ajv = new Ajv();
const _validParams = ajv.compile(paramsSchema);
function validParams(candidate: unknown): candidate is Params {
  return _validParams(candidate);
}

/**
 *  The `checkStatus` method is used to verify whether the agent is ready for the client
 *  to send requests. Typically it will be called either on process startup and/or when the
 *  user decides to configure Copilot.
 */
export default async function handleCheckStatus(ctx: Context, params: unknown): Promise<MethodResult<Result>> {
    if (validParams(params)) {
        const status = await ctx.get(AuthManager).checkAndUpdateStatus(ctx, params.options);
        return [status, null];
    } else {
          const errorMessages = extractAjvErrors(_validParams.errors as DefinedError[]);
          return [null, {
            code: ErrorCode.InvalidParams,
            message: 'Invalid params: ' + errorMessages.join(';')
        }];
    }
}
