
import { ErrorCode, extractAjvErrors } from '../rpc';
import { MethodResult } from './methods';
import Ajv, { DefinedError } from 'ajv';
import { GitHubDeviceFlow } from '../auth/deviceFlow';
import { AuthManager } from '../auth/manager';
import { Context } from '../../../lib/src/context';

export type Params = {
    options?: {}
};

const paramsSchema = {
    type: 'object',
    properties: {
      options: {
          type: 'object',
          required: [],
          properties: {
          }
        },
      }
};

export type Result =
    // The user should be prompted to visit `verificationUri`, paste in `userCode` and
    // authorize access. It will take up to `interval` seconds after they do this for
    // authentication to complete. If they don't complete this within `expiresIn` seconds,
    // authentication will time out.
    //
    // After prompting the user, call `signInConfirm` to wait for them to do it.
    {
        status: "PromptUserDeviceFlow";
        userCode: string;
        verificationUri: string;
        expiresIn: number;
        interval: number;
    }
    |
    // The user has already been authenticated and doesn't need to authenticate again.
    {
        status: "AlreadySignedIn";
        user: string;
    };

const ajv = new Ajv();
const _validParams = ajv.compile(paramsSchema);
function validParams(candidate: unknown): candidate is Params {
  return _validParams(candidate);
}

/**
 * The `signInInitiate` method should be called after the agent returns an `AuthStatus` of `NotSignedIn`.
 */
export default async function handleInitiateSignIn(ctx: Context, params: unknown): Promise<MethodResult<Result>> {
    if (validParams(params)) {
        const currentStatus = await ctx.get(AuthManager).checkAndUpdateStatus(ctx);
        if (currentStatus.status === "OK" ) {
            return [{ status: "AlreadySignedIn", user: currentStatus.user }, null];
        }
        const deviceFlow = await ctx.get(GitHubDeviceFlow).getToken();
        const waitForAuth = deviceFlow.waitForAuth.then(async authed => {
            await ctx.get(AuthManager).setAuthRecord(authed);
            return await ctx.get(AuthManager).checkAndUpdateStatus(ctx);
        });
        ctx.get(AuthManager).setPendingSignIn(waitForAuth);

        const result: Result = {
            status: "PromptUserDeviceFlow",
            userCode: deviceFlow.user_code,
            verificationUri: deviceFlow.verification_uri,
            expiresIn: deviceFlow.expires_in,
            interval: deviceFlow.interval
        };
        return [result, null];
    } else {
          const errorMessages = extractAjvErrors(_validParams.errors as DefinedError[]);
          return [null, {
            code: ErrorCode.InvalidParams,
            message: 'Invalid params: ' + errorMessages.join(';')
        }];
    }
}
