import { fetch } from "fetch-h2";

import Ajv, { JSONSchemaType } from 'ajv';

let SNIPPY_URL = 'https://origin-tracker.githubapp.com/twirp/github.snippy.Snippy/Match';
let SNIPPY_WINDOW_SIZE = 60;

// For typesafety
export type SnippyToken = { _brand: "snippytoken", token: string }

/** Requests for the Snippy web app */
interface SnippyRequest {
    source: string;
}

export interface SnippyError {
    type: "err"
    code: string;
    msg: string
    meta?: any;
}

/**
 *  A matching snippet as returned by Snippy
 *   - `matchedSource`: The substring of the submitted `source` that had a match.
 *   - `url`: An example URL that contained matching source.
 *   - `totalMatches`: The total number of matches with `matchedSource`.
 */
interface Snippet {
    matched_source: string;
    url: string;
    occurrences: number;
}

interface SnippyMatch {
    type: "match";
    snippets: Snippet[];
}

type SnippyResponse = SnippyError | SnippyMatch;

const ajv = new Ajv({"coerceTypes": true});
const snippetsSchema: JSONSchemaType<Snippet[]> = {
    "type": "array",
    "items": {
        "type": "object",
        "properties": {
            "matched_source": { "type": "string" },
            "url": { "type": "string" },
            "occurrences": { "type": "integer" },
        },
        "required": ["matched_source", "url", "occurrences"]
    }
};
const validateSnippets = ajv.compile(snippetsSchema);

/** Call Snippy on the given source and return the matches. */
async function callSnippy(authToken: SnippyToken, source: string): Promise<SnippyResponse> {
    // TODO Optimization: Don't call snippy when source is too short
    let requestBody : SnippyRequest = { source: source };
    let body = JSON.stringify(requestBody);
    return fetch(SNIPPY_URL, {
        // TODO: Make sure all necessary escaping is being done here
        method: 'POST',
        body: body,
        headers: { "Content-Type": "application/json",
                   "Authorization": `Bearer ${authToken.token}` }
    }).then(response => {
        return response.json()
    }).then((jsonResponse: any) => {
        if (jsonResponse.snippets) {
            if (!validateSnippets(jsonResponse.snippets)) {
                return {
                    type: "err" as const,
                    code: "invalid response",
                    msg: `invalid snippet returned: ${JSON.stringify(validateSnippets.errors)}`,
                }
            } else {
                return {
                    type: "match" as const,
                    snippets: jsonResponse.snippets
                }
            }
        } else {
            return {
                type: "err" as const,
                code: JSON.stringify(jsonResponse.code),
                msg: JSON.stringify(jsonResponse.msg),
                meta: jsonResponse.meta
            }
        }
    }).catch(e => {
        return {
            type: "err" as const,
            code: "network error",
            msg: JSON.stringify(e)
        };
    });
}

// Snippy lexeme regex
let snippyLexemeRegex = new RegExp("[_\\p{L}\\p{Nd}]+|====+|----+|####+|////+|\\*\\*\\*\\*+|[\\p{P}\\p{S}]","gu");

/** Return the offset after the first `n` lexemes of `text`, counted in Snippy lexemes */
export function offsetFirstLexemes(text: string, n: number): number {
    let i = 0;
    let m: RegExpExecArray | null;
    snippyLexemeRegex.lastIndex = 0;
    do {
        m = snippyLexemeRegex.exec(text);
        if (m) {
            i += 1;
            if (i >= n) {
                return snippyLexemeRegex.lastIndex;
            }
        }
    } while (m);
    // The whole text is less than n tokens
    return text.length;
}

/** Return the offset at the beginning of the last `n` lexemes of `text`, counted in Snippy lexemes */
export function offsetLastLexemes(text: string, n: number): number {
    let textRev = text.split("").reverse().join("");
    let offsetRev = offsetFirstLexemes(textRev, n);
    return textRev.length - offsetRev;
}

/** Return the number of lexemes in the supplied text */
export function lexemeLength(text: string): number {
    let i = 0;
    let m: RegExpExecArray | null;
    snippyLexemeRegex.lastIndex = 0;
    do {
        m = snippyLexemeRegex.exec(text);
        if (m) {
            i += 1;
        }
    } while (m);
    return i;
}


/**
 *  A matching snippet in a source string. After a `SnippyResponseMatch` is
 *  returned asynchronously, we recheck in an updated source string, and return
 *  synchronously the range in which the match is currently  found (if any).
 *   - `matched_source`: The matched source
 *   - `url`: An example URL that contained matching source.
 *   - `totalMatches`: The total number of matches with `matchedSource`.
 *   - `foundAt`: An offset in the updated current string where the match was found, or
 *     undefined if it was no longer present.
 */
export interface SnippyStringMatch {
    matchedSource: string;
    url: string;
    occurrences: number;
    foundAt: number | undefined;
}

export type MatchStringCallback = {
    type: "match",
    fn: (newText: string) => (SnippyStringMatch[])
}

export type SnippyResult = MatchStringCallback | SnippyError;


/**
 * Use Snippy to check for a match in the supplied string around a range of interest.
 * - `text`: The text to check for a match.
 * - `interestRange`: The range of interest in the text. Snippy will check for
 *   any match that overlaps with this range, including an appropriate window both before and
 *   after the range.
 */
export async function checkInString(authToken: SnippyToken, text: string, interestRange?: [number, number]): Promise<MatchStringCallback | SnippyError> {
    var source: string | null;
    let fromIndex: number, toIndex: number;
    if (interestRange === undefined) {
        fromIndex = 0;
        toIndex = text.length;
    } else {
        fromIndex = offsetLastLexemes(text.slice(0, interestRange[0]), SNIPPY_WINDOW_SIZE);
        toIndex = interestRange[1] + offsetFirstLexemes(text.slice(interestRange[1]), SNIPPY_WINDOW_SIZE);
    }
    source = text.slice(fromIndex, toIndex);
    let response = await callSnippy(authToken, source );
    if (response.type === "err") {
        return response;
    } else {
        let snippets = response.snippets;
        return {
            type: "match",
            fn: function (newText: string) {
                return snippets.map((match:Snippet) : SnippyStringMatch => {
                    // Try first to match close to the inserted range.
                    let matchOffset = newText.slice(fromIndex, toIndex).indexOf(match.matched_source);
                    if (matchOffset !== -1) {
                        matchOffset += fromIndex;
                    } else {
                        // If this fails, do global match
                        matchOffset = newText.indexOf(match.matched_source);
                    }
                    return {
                        matchedSource: match.matched_source,
                        url: match.url,
                        occurrences: match.occurrences,
                        foundAt: matchOffset > -1 ? matchOffset : undefined,
                    };
                })
            }
        }
    }
}