import { SHA256 } from 'crypto-js';


export function hashContents(content: string): string {
    return SHA256(content).toString();
}

export class LRUCache<T> {
    private values = new Map<string, T>();
    private lruKeys: string[] = [];
    private size: number;

    // constructor
    constructor(size = 10) {
        this.size = size;
    }

    private removeKeyFromLRU(key: string) {
        // Check if lruKeys array contains the key
        const index = this.lruKeys.indexOf(key);
        if (index !== -1) {
            // Remove the key from the lry array
            this.lruKeys.splice(index, 1);
        }
    }

    private touchKeyInLRU(key: string) {
        this.removeKeyFromLRU(key);
        this.lruKeys.push(key);
    }

    clear() {
        this.values.clear();
        this.lruKeys = [];
    }

    deleteKey(key: string) {
        this.removeKeyFromLRU(key);
        const tree = this.values.get(key);
        if (tree !== undefined) {
            this.values.delete(key);
        }
    }

    get(key: string): T | undefined {
        if (this.values.has(key)) {
            const entry = this.values.get(key);
            // Add the key to the end of the lruKeys array
            this.touchKeyInLRU(key);
            return entry;
        }

        return undefined;
    }

    put(key: string, value: T) {
        let maybeKeyToDelete: string[] = [];
        if (this.values.has(key)) {
            maybeKeyToDelete = [key];
        } else if (this.lruKeys.length >= this.size) {
            // least-recently used cache eviction strategy
            maybeKeyToDelete = this.lruKeys.splice(0, 1);
        }

        // Delete
        for (const keyToDelete of maybeKeyToDelete) {
            this.deleteKey(keyToDelete);
        }

        this.values.set(key, value);
        this.touchKeyInLRU(key);
    }
}